files.style.css:
:root {
    --bg-dark: #0a0a0d;
    --bg-medium: #1a1a2e;
    --bg-light: #2c2c4d;
    --text-primary: #e0e0e0;
    --text-secondary: #a0a0a0;
    --accent-blue: #00bfff; /* Deep Sky Blue */
    --accent-purple: #8a2be2; /* Blue Violet */
    --glow-color-blue: rgba(0, 191, 255, 0.6);
    --glow-color-purple: rgba(138, 43, 226, 0.6);
    --border-color: rgba(60, 60, 90, 0.5);
    --card-bg: rgba(26, 26, 46, 0.8);
    --card-border-glow: rgba(0, 191, 255, 0.2);
    --positive-color: #00ff80; /* Bright Green */
    --negative-color: #ff4500; /* Orange Red */
    --font-orbitron: 'Orbitron', sans-serif;
    --font-montserrat: 'Montserrat', sans-serif;
    --spacing-xs: 0.5rem;
    --spacing-sm: 1rem;
    --spacing-md: 1.5rem;
    --spacing-lg: 2rem;
    --spacing-xl: 3rem;
    --border-radius: 8px;
    --shadow-intensity: 0.8;
}

/* Global Resets & Body Styling */
* {
    margin: 0;
    padding: 0;
    box-sizing: border-box;
}

body {
    font-family: var(--font-montserrat);
    background-color: var(--bg-dark);
    color: var(--text-primary);
    line-height: 1.6;
    overflow-x: hidden; /* Prevent horizontal scroll */
    min-height: 100vh;
    display: flex;
    flex-direction: column;
    background: radial-gradient(circle at top left, rgba(0, 191, 255, 0.1), transparent 50%),
                radial-gradient(circle at bottom right, rgba(138, 43, 226, 0.1), transparent 50%),
                var(--bg-dark);
    animation: backgroundGlow 15s infinite alternate;
}

@keyframes backgroundGlow {
    0% { background-position: 0% 0%; }
    100% { background-position: 100% 100%; }
}

#app {
    display: flex;
    flex-direction: column;
    min-height: 100vh;
    width: 100%;
    max-width: 1920px; /* Max width for large screens */
    margin: 0 auto;
    padding: var(--spacing-md);
    gap: var(--spacing-lg);
}

/* Header */
.dashboard-header {
    display: flex;
    justify-content: space-between;
    align-items: center;
    padding: var(--spacing-md) var(--spacing-lg);
    background: rgba(26, 26, 46, 0.6);
    border-bottom: 1px solid var(--border-color);
    box-shadow: 0 0 20px var(--glow-color-purple);
    border-radius: var(--border-radius);
    margin-bottom: var(--spacing-lg);
    animation: headerFadeIn 1s ease-out forwards;
}

@keyframes headerFadeIn {
    from { opacity: 0; transform: translateY(-20px); }
    to { opacity: 1; transform: translateY(0); }
}

.logo {
    font-family: var(--font-orbitron);
    font-size: var(--spacing-xl);
    font-weight: 700;
    color: var(--accent-blue);
    text-shadow: 0 0 10px var(--glow-color-blue);
    letter-spacing: 2px;
}

.main-nav ul {
    list-style: none;
    display: flex;
    gap: var(--spacing-lg);
}

.main-nav a {
    text-decoration: none;
    color: var(--text-secondary);
    font-weight: 600;
    padding: var(--spacing-xs) var(--spacing-sm);
    border-radius: var(--border-radius);
    transition: all 0.3s ease;
    position: relative;
}

.main-nav a::before {
    content: '';
    position: absolute;
    bottom: -5px;
    left: 50%;
    width: 0%;
    height: 2px;
    background: var(--accent-blue);
    transition: width 0.3s ease-out, left 0.3s ease-out;
}

.main-nav a:hover {
    color: var(--text-primary);
    text-shadow: 0 0 5px var(--glow-color-blue);
}

.main-nav a:hover::before {
    width: 100%;
    left: 0%;
}

.main-nav a.active {
    color: var(--accent-blue);
    text-shadow: 0 0 8px var(--glow-color-blue);
    border: 1px solid var(--accent-blue);
    box-shadow: 0 0 15px var(--glow-color-blue);
    background: rgba(0, 191, 255, 0.1);
}

.user-profile {
    display: flex;
    align-items: center;
    gap: var(--spacing-sm);
}

.user-profile .username {
    font-family: var(--font-orbitron);
    color: var(--text-primary);
    font-size: var(--spacing-sm);
}

.user-profile .avatar {
    width: 40px;
    height: 40px;
    background: linear-gradient(45deg, var(--accent-purple), var(--accent-blue));
    border-radius: 50%;
    border: 2px solid var(--glow-color-purple);
    box-shadow: 0 0 10px var(--glow-color-purple);
    transition: transform 0.3s ease;
}

.user-profile .avatar:hover {
    transform: scale(1.1) rotate(10deg);
    box-shadow: 0 0 15px var(--glow-color-blue);
}

/* Main Content */
.dashboard-content {
    flex-grow: 1;
    display: grid;
    grid-template-columns: 1fr;
    gap: var(--spacing-lg);
}

@media (min-width: 1024px) {
    .dashboard-content {
        grid-template-columns: 2fr 1fr;
        grid-template-areas:
            "metrics metrics"
            "products charts";
    }
    .section-metrics { grid-area: metrics; }
    .section-products { grid-area: products; }
    .section-charts { grid-area: charts; }
}

/* Section Styling */
.section-title {
    font-family: var(--font-orbitron);
    font-size: var(--spacing-lg);
    color: var(--accent-blue);
    text-shadow: 0 0 8px var(--glow-color-blue);
    margin-bottom: var(--spacing-md);
    border-bottom: 2px solid rgba(0, 191, 255, 0.3);
    padding-bottom: var(--spacing-xs);
    display: flex;
    align-items: center;
    gap: var(--spacing-xs);
    animation: titleFadeIn 1s ease-in forwards;
}

@keyframes titleFadeIn {
    from { opacity: 0; transform: translateX(-20px); }
    to { opacity: 1; transform: translateX(0); }
}

.live-indicator {
    font-size: var(--spacing-sm);
    color: var(--positive-color);
    text-shadow: 0 0 5px var(--positive-color);
    animation: pulse 1.5s infinite alternate;
}

@keyframes pulse {
    0% { transform: scale(1); opacity: 0.8; }
    100% { transform: scale(1.05); opacity: 1; }
}

/* Metrics Grid */
.metrics-grid {
    display: grid;
    grid-template-columns: repeat(auto-fit, minmax(220px, 1fr));
    gap: var(--spacing-md);
    margin-bottom: var(--spacing-lg);
}

.metric-card {
    background: var(--card-bg);
    border: 1px solid var(--border-color);
    border-radius: var(--border-radius);
    padding: var(--spacing-md);
    display: flex;
    flex-direction: column;
    align-items: flex-start;
    position: relative;
    overflow: hidden;
    box-shadow: 0 0 15px var(--card-border-glow);
    transition: all 0.3s ease;
    animation: fadeIn 0.8s ease-out forwards;
}

.metric-card:nth-child(1) { animation-delay: 0.1s; }
.metric-card:nth-child(2) { animation-delay: 0.2s; }
.metric-card:nth-child(3) { animation-delay: 0.3s; }
.metric-card:nth-child(4) { animation-delay: 0.4s; }

@keyframes fadeIn {
    from { opacity: 0; transform: translateY(20px); }
    to { opacity: 1; transform: translateY(0); }
}

.metric-card::before {
    content: '';
    position: absolute;
    top: 0;
    left: 0;
    width: 100%;
    height: 5px;
    background: linear-gradient(90deg, transparent, var(--accent-blue), transparent);
    animation: borderScan 2s infinite linear;
    transform: translateX(-100%);
    opacity: 0;
}

.metric-card:hover::before {
    opacity: 1;
}

@keyframes borderScan {
    0% { transform: translateX(-100%); }
    100% { transform: translateX(100%); }
}

.metric-card:hover {
    transform: translateY(-5px) scale(1.02);
    box-shadow: 0 0 25px var(--glow-color-blue), 0 0 5px var(--glow-color-purple);
    border-color: var(--accent-blue);
}

.metric-label {
    font-size: var(--spacing-sm);
    color: var(--text-secondary);
    margin-bottom: var(--spacing-xs);
}

.metric-value {
    font-family: var(--font-orbitron);
    font-size: var(--spacing-xl);
    font-weight: 700;
    color: var(--text-primary);
    text-shadow: 0 0 8px var(--glow-color-blue);
    margin-bottom: var(--spacing-xs);
}

.metric-change {
    font-size: var(--spacing-sm);
    font-weight: 600;
}

.metric-change.positive {
    color: var(--positive-color);
    text-shadow: 0 0 5px rgba(0, 255, 128, 0.5);
}

.metric-change.negative {
    color: var(--negative-color);
    text-shadow: 0 0 5px rgba(255, 69, 0, 0.5);
}

/* Product Grid */
.product-grid {
    display: grid;
    grid-template-columns: repeat(auto-fit, minmax(250px, 1fr));
    gap: var(--spacing-md);
    margin-bottom: var(--spacing-lg);
}

.product-card {
    background: var(--card-bg);
    border: 1px solid var(--border-color);
    border-radius: var(--border-radius);
    overflow: hidden;
    position: relative;
    box-shadow: 0 0 10px rgba(0, 191, 255, 0.1);
    transition: all 0.3s ease;
    animation: cardEntry 0.5s ease-out forwards;
    display: flex;
    flex-direction: column;
    justify-content: space-between;
}

.product-card:hover {
    transform: translateY(-8px) scale(1.03);
    box-shadow: 0 0 20px var(--glow-color-blue), 0 0 8px var(--glow-color-purple);
    border-color: var(--accent-blue);
}

.product-card img {
    width: 100%;
    height: 180px;
    object-fit: cover;
    display: block;
    border-bottom: 1px solid var(--border-color);
    transition: transform 0.3s ease;
}

.product-card:hover img {
    transform: scale(1.05);
}

.product-info {
    padding: var(--spacing-md);
    flex-grow: 1;
    display: flex;
    flex-direction: column;
    justify-content: space-between;
}

.product-name {
    font-family: var(--font-orbitron);
    font-size: var(--spacing-md);
    margin-bottom: var(--spacing-xs);
    color: var(--text-primary);
    text-shadow: 0 0 5px rgba(255, 255, 255, 0.2);
    overflow: hidden;
    text-overflow: ellipsis;
    white-space: nowrap;
}

.product-price {
    font-family: var(--font-orbitron);
    font-size: var(--spacing-lg);
    font-weight: 700;
    color: var(--positive-color);
    text-shadow: 0 0 8px rgba(0, 255, 128, 0.5);
    margin-bottom: var(--spacing-sm);
}

.add-to-cart-btn {
    background: linear-gradient(45deg, var(--accent-purple), var(--accent-blue));
    color: var(--text-primary);
    border: none;
    padding: var(--spacing-xs) var(--spacing-sm);
    border-radius: var(--border-radius);
    cursor: pointer;
    font-weight: 600;
    transition: all 0.3s ease;
    box-shadow: 0 0 10px rgba(138, 43, 226, 0.4);
    text-align: center;
    width: 100%;
}

.add-to-cart-btn:hover {
    transform: scale(1.05);
    box-shadow: 0 0 15px var(--glow-color-blue), 0 0 10px var(--glow-color-purple);
    background: linear-gradient(45deg, var(--accent-blue), var(--accent-purple));
    opacity: 0.9;
}

@keyframes cardEntry {
    from { opacity: 0; transform: scale(0.9) translateY(20px); }
    to { opacity: 1; transform: scale(1) translateY(0); }
}

/* Charts Section */
.charts-container {
    display: grid;
    grid-template-columns: 1fr;
    gap: var(--spacing-md);
    margin-bottom: var(--spacing-lg);
}

@media (min-width: 768px) {
    .charts-container {
        grid-template-columns: repeat(auto-fit, minmax(300px, 1fr));
    }
}

.chart-card {
    background: var(--card-bg);
    border: 1px solid var(--border-color);
    border-radius: var(--border-radius);
    padding: var(--spacing-md);
    box-shadow: 0 0 15px var(--glow-color-purple);
    transition: all 0.3s ease;
    animation: fadeIn 1s ease-out forwards;
}

.chart-card:hover {
    box-shadow: 0 0 25px var(--glow-color-purple), 0 0 10px var(--glow-color-blue);
    border-color: var(--accent-purple);
}

.chart-card h3 {
    font-family: var(--font-orbitron);
    font-size: var(--spacing-md);
    color: var(--accent-purple);
    text-shadow: 0 0 5px var(--glow-color-purple);
    margin-bottom: var(--spacing-md);
    border-bottom: 1px solid rgba(138, 43, 226, 0.3);
    padding-bottom: var(--spacing-xs);
}

canvas {
    max-width: 100%;
    height: auto;
}

/* Responsive Adjustments */
@media (max-width: 768px) {
    .dashboard-header {
        flex-direction: column;
        gap: var(--spacing-md);
        padding: var(--spacing-md);
    }
    .main-nav ul {
        flex-wrap: wrap;
        justify-content: center;
        gap: var(--spacing-sm);
    }
    .main-nav a {
        padding: var(--spacing-xs);
        font-size: 0.9em;
    }
    .user-profile {
        margin-top: var(--spacing-sm);
    }
    .dashboard-content {
        padding: var(--spacing-sm);
        gap: var(--spacing-md);
    }
    .section-title {
        font-size: var(--spacing-md);
        text-align: center;
        justify-content: center;
    }
    .metric-value {
        font-size: var(--spacing-lg);
    }
    .product-grid {
        grid-template-columns: 1fr; /* Single column on small screens */
    }
    .charts-container {
        grid-template-columns: 1fr;
    }
}

