document.addEventListener('DOMContentLoaded', () => {
    const app = document.getElementById('app');
    if (!app) {
        console.error('Root element #app not found!');
        return;
    }

    // --- Dashboard Metrics Data ---
    const dashboardMetrics = [
        { id: 'sales', title: 'Total Sales', value: 125000, unit: '$', change: 5.2, icon: '📈' },
        { id: 'orders', title: 'New Orders', value: 245, unit: '', change: 12, icon: '🛒' },
        { id: 'revenue', title: 'Avg. Revenue', value: 512, unit: '$', change: -1.5, icon: '💰' },
        { id: 'customers', title: 'Active Users', value: 1890, unit: '', change: 8.1, icon: '👥' }
    ];

    const dashboardMetricsContainer = document.getElementById('dashboard-metrics-container');

    function renderDashboardMetrics() {
        if (!dashboardMetricsContainer) return;

        dashboardMetricsContainer.innerHTML = ''; // Clear previous content
        dashboardMetrics.forEach((metric, index) => {
            const changeClass = metric.change >= 0 ? 'positive' : 'negative';
            const changeArrow = metric.change >= 0 ? '↑' : '↓';
            const metricCard = document.createElement('div');
            metricCard.className = `metric-card fade-in delay-${index + 1}`;
            metricCard.innerHTML = `
                <div class="metric-icon">${metric.icon}</div>
                <div class="metric-title">${metric.title}</div>
                <div class="metric-value">${metric.unit}${metric.value.toLocaleString()}</div>
                <div class="metric-change ${changeClass}">
                    ${changeArrow} ${Math.abs(metric.change)}%
                </div>
            `;
            dashboardMetricsContainer.appendChild(metricCard);
        });
    }

    function updateDashboardMetrics() {
        dashboardMetrics.forEach(metric => {
            const change = (Math.random() * 10 - 5).toFixed(1); // -5% to +5%
            metric.value = Math.max(0, metric.value + Math.round(metric.value * (change / 100)));
            metric.change = parseFloat(change);
        });
        // Re-render to update values and classes
        renderDashboardMetrics();
    }

    // --- Real-time Chart ---
    const ctx = document.getElementById('realtime-sales-chart')?.getContext('2d');
    let salesChart;

    if (ctx) {
        const initialData = Array.from({ length: 15 }, () => Math.floor(Math.random() * 500) + 1000); // 15 data points
        const labels = Array.from({ length: 15 }, (_, i) => `T-${14 - i}s`); // Labels like T-14s, T-13s, ... T-0s

        salesChart = new Chart(ctx, {
            type: 'line',
            data: {
                labels: labels,
                datasets: [{
                    label: 'Live Sales',
                    data: initialData,
                    borderColor: 'rgba(77, 208, 225, 1)', // --color-primary-medium
                    backgroundColor: 'rgba(77, 208, 225, 0.2)',
                    borderWidth: 2,
                    pointRadius: 4,
                    pointBackgroundColor: 'rgba(77, 208, 225, 1)',
                    pointBorderColor: '#fff',
                    pointHoverRadius: 6,
                    fill: true,
                    tension: 0.3, // Smoother line
                }]
            },
            options: {
                responsive: true,
                maintainAspectRatio: false,
                animation: {
                    duration: 500, // Speed of updates
                    easing: 'easeOutQuart'
                },
                scales: {
                    x: {
                        grid: {
                            color: 'rgba(77, 208, 225, 0.1)',
                            drawBorder: false
                        },
                        ticks: {
                            color: 'var(--color-text-medium)',
                        }
                    },
                    y: {
                        beginAtZero: false,
                        grid: {
                            color: 'rgba(77, 208, 225, 0.1)',
                            drawBorder: false
                        },
                        ticks: {
                            color: 'var(--color-text-medium)',
                            callback: function(value) {
                                return `$${value.toLocaleString()}`;
                            }
                        }
                    }
                },
                plugins: {
                    legend: {
                        display: true,
                        labels: {
                            color: 'var(--color-primary-light)',
                            font: {
                                size: 14,
                                family: 'var(--font-body)'
                            }
                        }
                    },
                    tooltip: {
                        backgroundColor: 'rgba(28, 28, 58, 0.9)', // --color-bg-card
                        titleColor: 'var(--color-primary-light)',
                        bodyColor: 'var(--color-text-light)',
                        borderColor: 'var(--color-primary-medium)',
                        borderWidth: 1,
                        cornerRadius: 8,
                        displayColors: false,
                        callbacks: {
                            label: function(context) {
                                return `Sales: $${context.parsed.y.toLocaleString()}`;
                            }
                        }
                    }
                }
            }
        });
    }

    let chartTime = 0;
    function updateChartData() {
        if (!salesChart) return;

        // Remove the oldest data point and label
        salesChart.data.labels.shift();
        salesChart.data.datasets[0].data.shift();

        // Add a new data point and label
        chartTime++;
        const newValue = Math.floor(Math.random() * 500) + 1000 + (Math.sin(chartTime * 0.2) * 300); // Simulate some trend
        salesChart.data.labels.push(`Now`);
        salesChart.data.datasets[0].data.push(newValue);

        // Update the chart
        salesChart.update();
    }

    // --- Product Data ---
    const products = [
        {
            id: 1,
            name: 'Quantum Core Processor',
            category: 'Electronics',
            price: 799.99,
            imageUrl: 'https://images.unsplash.com/photo-1549492167-27e1f41b3186?ixlib=rb-4.0.3&ixid=MnwxMjA3fDB8MHxwaG90by1wYWdlfHx8fGVufDB8fHx8&auto=format&fit=crop&w=800&q=80'
        },
        {
            id: 2,
            name: 'Holographic Display Unit',
            category: 'Peripherals',
            price: 1299.00,
            imageUrl: 'https://images.unsplash.com/photo-1593450373070-e67c29fb143c?ixlib=rb-4.0.3&ixid=MnwxMjA3fDB8MHxzZWFyY2h8MTB8fGhvbG9ncmFwaGljfGVufDB8fDB8fA%3D%3D&auto=format&fit=crop&w=800&q=60'
        },
        {
            id: 3,
            name: 'Neural Interface Headset',
            category: 'Wearables',
            price: 499.50,
            imageUrl: 'https://images.unsplash.com/photo-1627916601620-ce9614c24151?ixlib=rb-4.0.3&ixid=MnwxMjA3fDB8MHxwaG90by1wYWdlfHx8fGVufDB8fHx8&auto=format&fit=crop&w=800&q=80'
        },
        {
            id: 4,
            name: 'Zero-Gravity Drone',
            category: 'Drones',
            price: 899.00,
            imageUrl: 'https://images.unsplash.com/photo-1522221650894-6d9bfe2b4d99?ixlib=rb-4.0.3&ixid=MnwxMjA3fDB8MHxzZWFyY2h8MTl8fGRyb25lJTIwZHVhbHxlbnwwfHwwfHx8MA%3D%3D&auto=format&fit=crop&w=800&q=60'
        },
        {
            id: 5,
            name: 'AI Smart Home Hub',
            category: 'Smart Home',
            price: 249.99,
            imageUrl: 'https://images.unsplash.com/photo-1601925345799-a316c04f9829?ixlib=rb-4.0.3&ixid=MnwxMjA3fDB8MHxzZWFyY2h8MTR8fHNtYXJ0JTIwaG9tZXxlbnwwfHwwfHx8MA%3D%3D&auto=format&fit=crop&w=800&q=60'
        },
        {
            id: 6,
            name: 'Bio-Luminescent Plant Grow Kit',
            category: 'Gardening',
            price: 159.00,
            imageUrl: 'https://images.unsplash.com/photo-1607592440939-246e7f9c2d15?ixlib=rb-4.0.3&ixid=MnwxMjA3fDB8MHxzZWFyY2h8NHx8YmlvbHVtaW5lc2NlbnQlMjBwbGFudHxlbnwwfHwwfHx8MA%3D%3D&auto=format&fit=crop&w=800&q=60'
        }
    ];

    const productListContainer = document.getElementById('product-list-container');

    function renderProducts() {
        if (!productListContainer) return;

        productListContainer.innerHTML = ''; // Clear previous content
        products.forEach((product, index) => {
            const productCard = document.createElement('div');
            productCard.className = `product-card fade-in delay-${index + 1}`;
            productCard.innerHTML = `
                <img src="${product.imageUrl}" alt="${product.name}" class="product-image">
                <div class="product-info">
                    <div>
                        <h3 class="product-title">${product.name}</h3>
                        <p class="product-category">${product.category}</p>
                    </div>
                    <div class="product-bottom">
                        <p class="product-price">$${product.price.toFixed(2)}</p>
                        <button class="add-to-cart-btn">Add to Cart</button>
                    </div>
                </div>
            `;
            productListContainer.appendChild(productCard);
        });
    }

    // --- Initial Renders and Real-time Updates ---
    renderDashboardMetrics();
    renderProducts();

    // Simulate real-time updates
    setInterval(updateDashboardMetrics, 5000); // Every 5 seconds
    setInterval(updateChartData, 1500); // Every 1.5 seconds

    // Add some initial animations (CSS handles most of it, but JS can trigger classes if needed)
    // For this design, the CSS `fade-in` with `animation-delay` is sufficient for initial load.
});

