files.style.css:
:root {
    --bg-color: #0b0f19;
    --card-bg: #1a1f2e;
    --primary-color: #00e6e6; /* Cyan */
    --accent-color: #ff00ff; /* Magenta */
    --text-color: #e0e0e0;
    --text-secondary-color: #a0a0a0;
    --border-color: rgba(0, 230, 230, 0.2);
    --glow-color-primary: rgba(0, 230, 230, 0.6);
    --glow-color-secondary: rgba(255, 0, 255, 0.4);
    --hover-glow: rgba(0, 230, 230, 0.8);

    --spacing-xs: 4px;
    --spacing-sm: 8px;
    --spacing-md: 16px;
    --spacing-lg: 24px;
    --spacing-xl: 32px;

    --border-radius: 8px;
    --font-heading: 'Orbitron', sans-serif;
    --font-body: 'Roboto Mono', monospace;

    --animation-duration: 0.8s;
    --transition-duration: 0.3s;
}

/* Global Resets and Base Styles */
*,
*::before,
*::after {
    margin: 0;
    padding: 0;
    box-sizing: border-box;
}

body {
    font-family: var(--font-body);
    background-color: var(--bg-color);
    color: var(--text-color);
    line-height: 1.6;
    overflow-x: hidden;
    display: flex;
    justify-content: center;
    align-items: flex-start;
    min-height: 100vh;
    padding: var(--spacing-xl);
    background: radial-gradient(circle at center, rgba(11, 15, 25, 0.8) 0%, rgba(0, 0, 0, 1) 100%);
    background-attachment: fixed;
}

#app {
    width: 100%;
    max-width: 1600px; /* Max width for the whole dashboard */
}

/* Animations */
@keyframes fadeIn {
    from { opacity: 0; transform: translateY(20px); }
    to { opacity: 1; transform: translateY(0); }
}

@keyframes pulseGlowPrimary {
    0% { box-shadow: 0 0 10px var(--glow-color-primary); }
    50% { box-shadow: 0 0 20px var(--glow-color-primary), 0 0 30px var(--glow-color-secondary); }
    100% { box-shadow: 0 0 10px var(--glow-color-primary); }
}

@keyframes pulseGlowSecondary {
    0% { border-color: rgba(0, 230, 230, 0.2); }
    50% { border-color: rgba(0, 230, 230, 0.5); }
    100% { border-color: rgba(0, 230, 230, 0.2); }
}

@keyframes onlinePulse {
    0% { box-shadow: 0 0 0 0 rgba(0, 255, 0, 0.7); }
    70% { box-shadow: 0 0 0 10px rgba(0, 255, 0, 0); }
    100% { box-shadow: 0 0 0 0 rgba(0, 255, 0, 0); }
}

/* Dashboard Header */
.dashboard-header {
    display: flex;
    justify-content: space-between;
    align-items: center;
    padding: var(--spacing-md) 0 var(--spacing-xl);
    margin-bottom: var(--spacing-lg);
    border-bottom: 1px solid var(--border-color);
    animation: fadeIn var(--animation-duration) ease-out;
}

.dashboard-title {
    font-family: var(--font-heading);
    font-size: 2.5rem;
    color: var(--primary-color);
    text-shadow: 0 0 10px var(--glow-color-primary), 0 0 20px var(--glow-color-primary);
    letter-spacing: 2px;
}

.status-indicator {
    display: flex;
    align-items: center;
    gap: var(--spacing-sm);
    font-size: 1rem;
    font-family: var(--font-heading);
    color: #fff;
    text-transform: uppercase;
    letter-spacing: 1px;
    padding: var(--spacing-sm) var(--spacing-md);
    border-radius: var(--border-radius);
    background-color: rgba(0, 0, 0, 0.3);
    border: 1px solid var(--border-color);
}

.status-indicator.online .dot {
    width: 10px;
    height: 10px;
    border-radius: 50%;
    background-color: #0f0;
    box-shadow: 0 0 8px #0f0;
    animation: onlinePulse 2s infinite;
}

.status-indicator.online .text {
    color: #0f0;
    text-shadow: 0 0 5px #0f0;
}

/* Dashboard Grid Layout */
.dashboard-grid {
    display: grid;
    grid-template-columns: repeat(auto-fit, minmax(280px, 1fr));
    gap: var(--spacing-lg);
}

/* Cards */
.card {
    background-color: var(--card-bg);
    border-radius: var(--border-radius);
    padding: var(--spacing-xl);
    border: 1px solid var(--border-color);
    box-shadow: 0 0 15px rgba(0, 230, 230, 0.1);
    transition: all var(--transition-duration) ease-in-out;
    animation: fadeIn var(--animation-duration) ease-out forwards;
    display: flex;
    flex-direction: column;
    justify-content: space-between; /* Ensure content stretches */
    min-height: 150px; /* Minimum height for cards */
}

.card:hover {
    transform: translateY(-5px);
    box-shadow: 0 0 25px var(--hover-glow), 0 0 40px rgba(255, 0, 255, 0.2);
    border-color: var(--primary-color);
}

.card-title {
    font-family: var(--font-heading);
    font-size: 1.3rem;
    color: var(--primary-color);
    margin-bottom: var(--spacing-md);
    text-shadow: 0 0 5px rgba(0, 230, 230, 0.4);
}

/* Overview Cards */
.overview-card {
    text-align: center;
    animation-delay: 0.1s; /* Stagger animation */
}

.overview-card:nth-child(2) { animation-delay: 0.2s; }
.overview-card:nth-child(3) { animation-delay: 0.3s; }

.metric-value {
    font-family: var(--font-heading);
    font-size: 2.8rem;
    font-weight: 700;
    color: var(--accent-color);
    text-shadow: 0 0 15px var(--glow-color-secondary), 0 0 25px rgba(255, 0, 255, 0.4);
    margin-bottom: var(--spacing-sm);
    animation: pulseGlowSecondary 4s infinite alternate;
}

.metric-label {
    font-size: 0.9rem;
    color: var(--text-secondary-color);
    text-transform: uppercase;
    letter-spacing: 1px;
}

/* Chart Card */
.chart-card {
    grid-column: 1 / -1; /* Spans all columns */
    animation-delay: 0.4s;
    min-height: 400px;
    display: flex;
    flex-direction: column;
}

.chart-container {
    flex-grow: 1;
    position: relative;
    padding: var(--spacing-sm);
}

/* Chart.js overrides to match theme */
.chart-card canvas {
    max-height: 100%;
}

/* Top Products & Recent Transactions */
.products-card, .transactions-card {
    animation-delay: 0.5s;
}

.product-list, .transaction-list {
    list-style: none;
    padding: 0;
    margin: 0;
    flex-grow: 1;
}

.product-list li, .transaction-list li {
    display: flex;
    justify-content: space-between;
    align-items: center;
    padding: var(--spacing-sm) 0;
    border-bottom: 1px dashed rgba(0, 230, 230, 0.1);
    font-size: 0.95rem;
    color: var(--text-secondary-color);
    transition: background-color var(--transition-duration) ease, transform var(--transition-duration) ease;
}

.product-list li:last-child, .transaction-list li:last-child {
    border-bottom: none;
}

.product-list li:hover, .transaction-list li:hover {
    background-color: rgba(0, 230, 230, 0.05);
    transform: translateX(5px);
}

.product-item-name, .transaction-item-details {
    color: var(--text-color);
    font-weight: 400;
}

.product-item-value, .transaction-item-amount {
    color: var(--primary-color);
    font-family: var(--font-heading);
    font-weight: 700;
    text-shadow: 0 0 5px rgba(0, 230, 230, 0.3);
}

.transaction-item-time {
    font-size: 0.8rem;
    color: var(--text-secondary-color);
}

/* Customer Activity Card */
.activity-card {
    animation-delay: 0.6s;
    display: flex;
    flex-direction: column;
    justify-content: space-around;
}

.activity-metric {
    text-align: center;
    margin-bottom: var(--spacing-md);
}

.activity-metric .metric-value {
    font-size: 2.2rem;
    margin-bottom: var(--spacing-xs);
}

.sparkline-chart-placeholder {
    display: flex;
    justify-content: space-around;
    align-items: flex-end;
    height: 60px;
    gap: 4px;
    padding-top: var(--spacing-sm);
    border-top: 1px dashed rgba(0, 230, 230, 0.1);
}

.sparkline-bar {
    width: 10px;
    background-color: var(--primary-color);
    opacity: 0.6;
    border-radius: 2px;
    transition: height 0.5s ease-out, background-color 0.5s ease;
    box-shadow: 0 0 5px var(--glow-color-primary);
}

/* Responsive Design */
@media (max-width: 1200px) {
    .dashboard-grid {
        grid-template-columns: repeat(auto-fit, minmax(250px, 1fr));
    }
}

@media (max-width: 768px) {
    body {
        padding: var(--spacing-lg);
    }

    .dashboard-header {
        flex-direction: column;
        align-items: flex-start;
        padding-bottom: var(--spacing-lg);
    }

    .dashboard-title {
        font-size: 2rem;
        margin-bottom: var(--spacing-md);
    }

    .status-indicator {
        width: fit-content;
    }

    .dashboard-grid {
        grid-template-columns: 1fr; /* Stack all cards on small screens */
    }

    .chart-card.full-width {
        grid-column: auto; /* Remove full width on mobile */
    }

    .card {
        padding: var(--spacing-lg);
        min-height: auto;
    }

    .metric-value {
        font-size: 2.5rem;
    }
}

@media (max-width: 480px) {
    body {
        padding: var(--spacing-md);
    }

    .dashboard-title {
        font-size: 1.8rem;
    }

    .card-title {
        font-size: 1.1rem;
    }

    .metric-value {
        font-size: 2rem;
    }
}

/* Chart.js specific styling for the theme */
canvas {
    font-family: var(--font-body) !important;
}

.chartjs-tooltip {
    background: rgba(var(--card-bg), 0.9) !important;
    border: 1px solid var(--border-color) !important;
    border-radius: var(--border-radius) !important;
    padding: var(--spacing-sm) !important;
    color: var(--text-color) !important;
    font-family: var(--font-body) !important;
    box-shadow: 0 0 10px var(--glow-color-primary) !important;
}

.chartjs-tooltip-header {
    margin-bottom: var(--spacing-xs) !important;
    padding-bottom: var(--spacing-xs) !important;
    border-bottom: 1px dashed rgba(0, 230, 230, 0.1) !important;
}

.chartjs-tooltip-title {
    color: var(--primary-color) !important;
    font-weight: 700 !important;
    font-size: 1rem !important;
}

.chartjs-tooltip-body {
    font-size: 0.9rem !important;
}

.chartjs-tooltip-body ul {
    list-style: none !important;
    padding: 0 !important;
    margin: 0 !important;
}

.chartjs-tooltip-body li {
    color: var(--text-color) !important;
}

