}

.nav-link {
    font-size: 1.1rem;
    font-weight: 600;
    color: var(--color-text-light);
    transition: color 0.3s ease, transform 0.3s ease;
    position: relative;
    padding: 5px 0;
}

.nav-link::after {
    content: '';
    position: absolute;
    bottom: 0;
    left: 0;
    width: 0;
    height: 2px;
    background-color: var(--color-accent);
    transition: width 0.3s ease;
}

.nav-link:hover {
    color: var(--color-accent);
    transform: translateY(-2px);
}

.nav-link:hover::after {
    width: 100%;
}

.hamburger {
    display: none;
    cursor: pointer;
    flex-direction: column;
    gap: 5px;
}

.hamburger .bar {
    width: 25px;
    height: 3px;
    background-color: var(--color-accent);
    transition: all 0.3s ease;
}

/* Hero Section */
.hero-section {
    position: relative;
    height: 100vh;
    display: flex;
    align-items: center;
    justify-content: center;
    text-align: center;
    color: var(--color-text-light);
    background-image: url('https://images.unsplash.com/photo-1509785307050-98c3b19f7433?ixlib=rb-4.0.3&ixid=MnwxMjA3fDB8MHxwaG90by1wYWdlfHx8fGVufDB8fHx8&auto=format&fit=crop&w=1920&q=80');
    background-size: cover;
    background-position: center;
    background-attachment: fixed; /* Parallax effect for hero */
    overflow: hidden;
}

.hero-section::before {
    content: '';
    position: absolute;
    top: 0;
    left: 0;
    width: 100%;
    height: 100%;
    background: rgba(0, 0, 0, 0.6); /* Dark overlay */
}

.hero-content {
    position: relative;
    z-index: 1;
    max-width: 800px;
    padding: var(--spacing-md);
}

.hero-content h1 {
    font-size: 4rem;
    margin-bottom: var(--spacing-md);
    line-height: 1.2;
    color: var(--color-accent);
    text-shadow: 0 4px 8px var(--color-shadow);
}

.hero-content p {
    font-size: 1.4rem;
    margin-bottom: var(--spacing-xl);
    font-weight: 300;
}

.cta-button {
    display: inline-block;
    background-color: var(--color-accent);
    color: var(--color-primary);
    padding: var(--spacing-md) var(--spacing-xl);
    border-radius: 50px;
    font-size: 1.2rem;
    font-weight: 700;
    text-transform: uppercase;
    letter-spacing: 1px;
    transition: all 0.3s ease;
    box-shadow: 0 6px 20px rgba(232, 220, 194, 0.3);
    position: relative;
    overflow: hidden;
    z-index: 1;
}

.cta-button:hover {
    background-color: var(--color-primary);
    color: var(--color-accent);
    transform: translateY(-3px);
    box-shadow: 0 8px 25px rgba(232, 220, 194, 0.4);
}

.cta-button::before {
    content: '';
    position: absolute;
    top: 0;
    left: -100%;
    width: 100%;
    height: 100%;
    background: linear-gradient(90deg, transparent, rgba(255, 255, 255, 0.3), transparent);
    transition: all 0.6s cubic-bezier(0.16, 1, 0.3, 1);
    z-index: -1;
}

.cta-button:hover::before {
    left: 100%;
}

/* Sections General Styling */
section {
    padding: var(--spacing-xxl) 0;
    position: relative;
    overflow: hidden;
}

.section-title {
    font-size: 3rem;
    text-align: center;
    margin-bottom: var(--spacing-xl);
    color: var(--color-accent);
    position: relative;
    padding-bottom: var(--spacing-sm);
}

.section-title::after {
    content: '';
    position: absolute;
    bottom: 0;
    left: 50%;
    transform: translateX(-50%);
    width: 80px;
    height: 4px;
    background-color: var(--color-accent);
    border-radius: 2px;
}

/* Our Story Section */
.story-section {
    background-color: var(--color-primary);
    background-image: url('https://images.unsplash.com/photo-1509785307050-98c3b19f7433?ixlib=rb-4.0.3&ixid=MnwxMjA3fDB8MHxwaG90by1wYWdlfHx8fGVufDB8fHx8&auto=format&fit=crop&w=1920&q=80');
    background-size: cover;
    background-position: center;
    background-attachment: fixed; /* Parallax effect */
    color: var(--color-text-light);
    position: relative;
    z-index: 1;
}

.story-section::before {
    content: '';
    position: absolute;
    top: 0;
    left: 0;
    width: 100%;
    height: 100%;
    background: rgba(44, 44, 44, 0.85); /* Darker overlay for text readability */
    z-index: -1;
}

.story-content {
    max-width: 800px;
    margin: 0 auto;
    text-align: center;
    padding: var(--spacing-lg);
    background-color: rgba(74, 44, 42, 0.8); /* Slightly transparent background for text block */
    border-radius: 10px;
    box-shadow: 0 8px 30px var(--color-shadow);
}

.story-content p {
    font-size: 1.1rem;
    margin-bottom: var(--spacing-md);
    line-height: 1.8;
}

/* Menu Section */
.menu-section {
    background-color: var(--color-secondary);
}

.menu-grid {
    display: grid;
    grid-template-columns: repeat(auto-fit, minmax(280px, 1fr));
    gap: var(--spacing-xl);
}

.menu-card {
    background-color: var(--color-primary);
    border-radius: 10px;
    overflow: hidden;
    box-shadow: 0 8px 25px var(--color-shadow);
    text-align: center;
    transition: transform 0.3s ease, box-shadow 0.3s ease;
    display: flex;
    flex-direction: column;
}

.menu-card:hover {
    transform: translateY(-10px);
    box-shadow: 0 12px 35px rgba(0, 0, 0, 0.6);
}

.menu-card img {
    width: 100%;
    height: 200px;
    object-fit: cover;
    display: block;
    transition: transform 0.3s ease;
}

.menu-card:hover img {
    transform: scale(1.05);
}

.menu-card h3 {
    font-size: 1.8rem;
    margin: var(--spacing-md) 0 var(--spacing-xs);
    color: var(--color-accent);
}

.menu-card p {
    font-size: 1rem;
    color: var(--color-text-light);
    padding: 0 var(--spacing-md);
    flex-grow: 1;
}

.menu-card .price {
    display: block;
    font-family: var(--font-heading);
    font-size: 1.5rem;
    font-weight: 700;
    color: var(--color-accent);
    margin-top: var(--spacing-md);
    margin-bottom: var(--spacing-md);
}

/* Gallery Section */
.gallery-section {
    background-color: var(--color-primary);
}

.gallery-grid {
    display: grid;
    grid-template-columns: repeat(auto-fit, minmax(250px, 1fr));
    gap: var(--spacing-md);
}

.gallery-grid img {
    width: 100%;
    height: 250px;
    object-fit: cover;
    border-radius: 8px;
    box-shadow: 0 4px 15px var(--color-shadow);
    transition: transform 0.3s ease, box-shadow 0.3s ease;
}

.gallery-grid img:hover {
    transform: scale(1.03);
    box-shadow: 0 8px 20px rgba(0, 0, 0, 0.6);
}

/* Location & Hours Section */
.location-section {
    background-color: var(--color-secondary);
}

.location-content {
    display: flex;
    flex-wrap: wrap;
    gap: var(--spacing-xl);
    justify-content: center;
    align-items: flex-start;
}

.address-hours {
    flex: 1;
    min-width: 300px;
    background-color: var(--color-primary);
    padding: var(--spacing-xl);
    border-radius: 10px;
    box-shadow: 0 8px 25px var(--color-shadow);
}

.address-hours h3 {
    font-size: 2rem;
    color: var(--color-accent);
    margin-bottom: var(--spacing-md);
}

.address-hours p,
.address-hours ul li {
    font-size: 1.1rem;
    margin-bottom: var(--spacing-sm);
    display: flex;
    align-items: center;
    gap: var(--spacing-sm);
}

.address-hours i {
    color: var(--color-accent);
    font-size: 1.2rem;
}

.map-embed {
    flex: 2;
    min-width: 400px;
    max-width: 600px;
    border-radius: 10px;
    overflow: hidden;
    box-shadow: 0 8px 25px var(--color-shadow);
}

.map-embed iframe {
    width: 100%;
    height: 450px;
    display: block; /* Remove extra space below iframe */
}

/* Newsletter Section */
.newsletter-section {
    background-color: var(--color-primary);
    text-align: center;
}

.newsletter-section p {
    font-size: 1.1rem;
    margin-bottom: var(--spacing-md);
}

.newsletter-form {
    max-width: 500px;
    margin: 0 auto;
    display: flex;
    flex-direction: column;
    gap: var(--spacing-md);
    padding: var(--spacing-lg);
    background-color: rgba(44, 44, 44, 0.7);
    border-radius: 10px;
    box-shadow: 0 8px 25px var(--color-shadow);
}

.newsletter-form .form-group {
    position: relative;
    width: 100%;
}

.newsletter-form input[type="email"] {
    width: 100%;
    padding: var(--spacing-md);
    border: 1px solid var(--color-accent);
    border-radius: 50px;
    background-color: rgba(255, 255, 255, 0.1);
    color: var(--color-text-light);
    font-size: 1rem;
    transition: border-color 0.3s ease, background-color 0.3s ease;
}

.newsletter-form input[type="email"]:focus {
    outline: none;
    border-color: var(--color-button-hover);
    background-color: rgba(255, 255, 255, 0.15);
}

.newsletter-form input[type="email"]::placeholder {
    color: rgba(255, 255, 255, 0.6);
}

.newsletter-form .cta-button {
    width: 100%;
    max-width: 250px;
    margin: 0 auto;
    padding: var(--spacing-sm) var(--spacing-lg);
    font-size: 1.1rem;
}

.error-message {
    color: #ff6b6b; /* Red for error */
    font-size: 0.9rem;
    margin-top: var(--spacing-xs);
    display: none; /* Hidden by default */
    text-align: left;
    padding-left: var(--spacing-md);
}

.success-message {
    color: #6bff95; /* Green for success */
    font-size: 1rem;
    margin-top: var(--spacing-md);
    display: none; /* Hidden by default */
}

/* Footer */
.footer {
    background-color: var(--color-primary);
    color: var(--color-text-light);
    padding: var(--spacing-xl) 0 var(--spacing-md);
    margin-top: auto; /* Push footer to bottom */
    box-shadow: 0 -2px 10px var(--color-shadow);
}

.footer-content {
    display: grid;
    grid-template-columns: repeat(auto-fit, minmax(200px, 1fr));
    gap: var(--spacing-lg);
    margin-bottom: var(--spacing-xl);
    text-align: center;
}

.footer-brand h3 {
    font-size: 1.8rem;
    margin-bottom: var(--spacing-sm);
    color: var(--color-accent);
}

.footer-brand p {
    font-size: 0.9rem;
    color: rgba(255, 255, 255, 0.8);
}

.footer-links h3,
.footer-social h3 {
    font-size: 1.4rem;
    margin-bottom: var(--spacing-sm);
    color: var(--color-accent);
}

.footer-links ul li {
    margin-bottom: var(--spacing-xs);
}

.footer-link {
    color: rgba(255, 255, 255, 0.8);
    transition: color 0.3s ease;
}

.footer-link:hover {
    color: var(--color-accent);
}

.social-icons a {
    display: inline-block;
    color: var(--color-accent);
    font-size: 1.5rem;
    margin: 0 var(--spacing-sm);
    transition: color 0.3s ease, transform 0.3s ease;
}

.social-icons a:hover {
    color: var(--color-button-hover);
    transform: translateY(-3px);
}

.footer-bottom {
    text-align: center;
    padding-top: var(--spacing-md);
    border-top: 1px solid rgba(255, 255, 255, 0.1);
    font-size: 0.9rem;
    color: rgba(255, 255, 255, 0.6);
}

/* Animations */
.animate-on-scroll {
    opacity: 0;
    transform: translateY(50px);
    transition: opacity 0.8s ease-out, transform 0.8s ease-out;
}

.animate-on-scroll.is-visible {
    opacity: 1;
    transform: translateY(0);
}

/* Hero Content Animations */
@keyframes fadeInUp {
    from {
        opacity: 0;
        transform: translateY(20px);
    }
    to {
        opacity: 1;
        transform: translateY(0);
    }
}

.animate-fade-in-up {
    opacity: 0;
    animation: fadeInUp 1s ease-out forwards;
}

.animate-fade-in-up.delay-1 {
    animation-delay: 0.3s;
}

.animate-fade-in-up.delay-2 {
    animation-delay: 0.6s;
}

/* Responsive Design */
@media (max-width: 992px) {
    .hero-content h1 {
        font-size: 3rem;
    }

    .hero-content p {
        font-size: 1.2rem;
    }

    .section-title {
        font-size: 2.5rem;
    }

    .menu-grid, .gallery-grid {
        grid-template-columns: repeat(auto-fit, minmax(220px, 1fr));
    }

    .location-content {
        flex-direction: column;
        align-items: center;
    }

    .map-embed {
        min-width: unset;
        width: 100%;
    }
}

@media (max-width: 768px) {
    .header .container {
        flex-wrap: wrap;
    }

    .logo {
        flex: 1;
        text-align: left;
    }

    .nav-menu {
        width: 100%;
        order: 2;
        margin-top: var(--spacing-md);
    }

    .nav-list {
        flex-direction: column;
        gap: var(--spacing-sm);
        display: none; /* Hidden by default for mobile */
        width: 100%;
        text-align: center;
        background-color: var(--color-primary);
        padding: var(--spacing-md) 0;
        border-top: 1px solid rgba(255, 255, 255, 0.1);
    }

    .nav-list.active {
        display: flex;
    }

    .nav-list li {
        width: 100%;
    }

    .nav-link {
        display: block;
        padding: var(--spacing-sm) 0;
    }

    .nav-link::after {
        left: 50%;
        transform: translateX(-50%);
    }

    .hamburger {
        display: flex;
        order: 1;
    }

    .hamburger.active .bar:nth-child(2) {
        opacity: 0;
    }

    .hamburger.active .bar:nth-child(1) {
        transform: translateY(8px) rotate(45deg);
    }

    .hamburger.active .bar:nth-child(3) {
        transform: translateY(-8px) rotate(-45deg);
    }

    .hero-content h1 {
        font-size: 2.5rem;
    }

    .hero-content p {
        font-size: 1rem;
    }

    .cta-button {
        font-size: 1rem;
        padding: var(--spacing-sm) var(--spacing-lg);
    }

    .section-title {
        font-size: 2rem;
    }

    .story-content {
        padding: var(--spacing-md);
    }

    .story-content p {
        font-size: 1rem;
    }

    .menu-grid, .gallery-grid {
        grid-template-columns: 1fr;
    }

    .newsletter-form input[type="email"] {
        font-size: 0.9rem;
    }

    .newsletter-form .cta-button {
        font-size: 1rem;
    }

    .footer-content {
        grid-template-columns: 1fr;
    }

    .footer-bottom {
        padding-top: var(--spacing-md);
    }
}

@media (max-width: 480px) {
    .hero-content h1 {
        font-size: 2rem;
    }

    .hero-content p {
        font-size: 0.9rem;
    }

    .section-title {
        font-size: 1.8rem;
    }

    .map-embed iframe {
        height: 300px;
    }
}

