document.addEventListener('DOMContentLoaded', () => {
    // Smooth Scrolling for Navigation Links
    document.querySelectorAll('.nav-link, .cta-button, .footer-link').forEach(anchor => {
        anchor.addEventListener('click', function(e) {
            e.preventDefault();
            const targetId = this.getAttribute('href');
            if (targetId.startsWith('#')) {
                const targetElement = document.querySelector(targetId);
                if (targetElement) {
                    const headerOffset = document.querySelector('.header').offsetHeight;
                    const elementPosition = targetElement.getBoundingClientRect().top + window.pageYOffset;
                    const offsetPosition = elementPosition - headerOffset;

                    window.scrollTo({
                        top: offsetPosition,
                        behavior: "smooth"
                    });

                    // Close mobile menu after clicking a link
                    if (document.querySelector('.hamburger').classList.contains('active')) {
                        toggleMobileMenu();
                    }
                }
            }
        });
    });

    // Mobile Navigation Toggle
    const hamburger = document.querySelector('.hamburger');
    const navList = document.querySelector('.nav-list');

    function toggleMobileMenu() {
        hamburger.classList.toggle('active');
        navList.classList.toggle('active');
        document.body.classList.toggle('no-scroll'); // Optional: disable scroll when menu is open
    }

    hamburger.addEventListener('click', toggleMobileMenu);

    // Scroll Animations with Intersection Observer
    const animateOnScrollElements = document.querySelectorAll('.animate-on-scroll');

    const observerOptions = {
        root: null, // viewport
        rootMargin: '0px',
        threshold: 0.1 // Trigger when 10% of the element is visible
    };

    const observer = new IntersectionObserver((entries, observer) => {
        entries.forEach(entry => {
            if (entry.isIntersecting) {
                entry.target.classList.add('is-visible');
                observer.unobserve(entry.target); // Stop observing once animated
            }
        });
    }, observerOptions);

    animateOnScrollElements.forEach(element => {
        observer.observe(element);
    });

    // Newsletter Form Client-Side Validation
    const newsletterForm = document.getElementById('newsletter-form');
    const emailInput = document.getElementById('email');
    const emailError = document.getElementById('email-error');
    const newsletterSuccess = document.getElementById('newsletter-success');

    newsletterForm.addEventListener('submit', function(e) {
        e.preventDefault();
        let isValid = true;

        // Reset messages
        emailError.style.display = 'none';
        newsletterSuccess.style.display = 'none';
        emailInput.classList.remove('invalid');

        // Validate email
        if (emailInput.value.trim() === '') {
            emailError.textContent = 'Email is required.';
            emailError.style.display = 'block';
            emailInput.classList.add('invalid');
            isValid = false;
        } else if (!isValidEmail(emailInput.value)) {
            emailError.textContent = 'Please enter a valid email address.';
            emailError.style.display = 'block';
            emailInput.classList.add('invalid');
            isValid = false;
        }

        if (isValid) {
            // In a real application, you would send this data to a backend.
            // For this vanilla JS example, we'll just simulate success.
            console.log('Newsletter subscription:', emailInput.value);
            newsletterSuccess.textContent = 'Thank you for subscribing!';
            newsletterSuccess.style.display = 'block';
            emailInput.value = ''; // Clear input
        }
    });

    function isValidEmail(email) {
        // Basic email regex for client-side validation
        const re = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
        return re.test(String(email).toLowerCase());
    }
});

