document.addEventListener('DOMContentLoaded', async () => {
  const app = document.getElementById('app');
  const productGrid = document.getElementById('productGrid');
  const chartCtx = document.getElementById('salesChart').getContext('2d');

  // Fetch products
  try {
    const resp = await fetch('https://fakestoreapi.com/products?limit=8');
    if (!resp.ok) throw new Error('Failed to fetch products');
    const products = await resp.json();
    productGrid.innerHTML = '';
    products.forEach(p => {
      const card = document.createElement('div');
      card.className = 'product-card';
      card.innerHTML = '<img src=\' + p.image + '\' alt=\' + p.title + '\'><div class=\'content\'><h2>' + p.title + '</h2><p>' + p.description.substring(0,100) + '...</p><div class=\'price\'>$' + p.price.toFixed(2) + '</div><button class=\'btn\'>Add to Cart</button></div>';
      productGrid.appendChild(card);
    });
  } catch (err) {
    console.error(err);
    productGrid.textContent = 'Unable to load products.';
  }

  // Fetch market chart data (Ethereum price last 7 days)
  try {
    const chartResp = await fetch('https://api.coingecko.com/api/v3/coins/ethereum/market_chart?vs_currency=usd&days=7');
    if (!chartResp.ok) throw new Error('Failed to fetch chart data');
    const chartData = await chartResp.json();
    const prices = chartData.prices; // [ [timestamp, price], ... ]
    const labels = prices.map(p => new Date(p[0]).toLocaleDateString(undefined, {month:'short', day:'numeric'}));
    const data = prices.map(p => p[1]);

    new Chart(chartCtx, {
      type: 'line',
      data: {
        labels,
        datasets: [{
          label: 'Ethereum Price (USD)',
          data,
          borderColor: '#6366f1',
          backgroundColor: 'rgba(99,102,241,0.1)',
          tension:0.3,
          fill:true,
          pointRadius:0,
          borderWidth:2
        }]
      },
      options: {
        responsive:true,
        maintainAspectRatio:false,
        plugins:{
          legend:{labels:{color:'#e5e5e5'}},
          tooltip:{backgroundColor:'rgba(0,0,0,0.7)', titleColor:'#fff', bodyColor:'#fff'}
        },
        scales:{
          x:{grid:{color:'rgba(255,255,255,0.05)'}, ticks:{color:'#e5e5e5'}},
          y:{grid:{color:'rgba(255,255,255,0.05)'}, ticks:{color:'#e5e5e5'}}
        }
      }
    });
  } catch (err) {
    console.error(err);
    // fallback simple chart
    new Chart(chartCtx, {
      type:'line',
      data:{labels:[], datasets:[{label:'Data unavailable', data:[], borderColor:'#6366f1'}]},
      options:{responsive:true, maintainAspectRatio:false}
    });
  }
});

