*, *::before, *::after {
    box-sizing: border-box;
    margin: 0;
    padding: 0;
}

:root {
    --black: #000000;
    --white: #FFFFFF;
    --red: #FF3B30;
    --green: #00C853;
    --yellow: #FFCC00;
    --blue: #007AFF;
    --pink: #FF2D92;
    --orange: #FF9500;
    --purple: #AF52DE;
    --border-width: 4px;
    --shadow-offset: 6px;
    --shadow-color: var(--black);
    --font-display: 'Press Start 2P', monospace;
    --font-body: 'Courier New', Courier, monospace;
}

body {
    background-color: var(--black);
    background-image:
        linear-gradient(45deg, #111 25%, transparent 25%),
        linear-gradient(-45deg, #111 25%, transparent 25%),
        linear-gradient(45deg, transparent 75%, #111 75%),
        linear-gradient(-45deg, transparent 75%, #111 75%);
    background-size: 20px 20px;
    background-position: 0 0, 0 10px, 10px -10px, -10px 0px;
    background-attachment: fixed;
    display: flex;
    justify-content: center;
    align-items: center;
    min-height: 100vh;
    padding: 16px;
    font-family: var(--font-body);
}

.calculator-wrapper {
    width: 100%;
    max-width: 420px;
    position: relative;
}

.calculator {
    background-color: var(--white);
    border: var(--border-width) solid var(--black);
    border-radius: 0;
    box-shadow: var(--shadow-offset) var(--shadow-offset) 0px var(--black);
    padding: 24px;
    position: relative;
}

.calc-label {
    font-family: var(--font-display);
    font-size: 10px;
    color: var(--black);
    text-align: center;
    margin-bottom: 16px;
    letter-spacing: 2px;
}

.memory-indicator {
    position: absolute;
    top: 12px;
    right: 12px;
    font-family: var(--font-display);
    font-size: 8px;
    color: var(--yellow);
    background: var(--black);
    padding: 4px 6px;
    border: 2px solid var(--yellow);
    display: none;
}

.memory-indicator.active {
    display: block;
}

.display-container {
    background-color: #0a0a0a;
    border: var(--border-width) solid var(--black);
    padding: 16px;
    margin-bottom: 20px;
    position: relative;
    overflow: hidden;
    min-height: 100px;
    display: flex;
    flex-direction: column;
    justify-content: flex-end;
    align-items: flex-end;
}

.display-scanlines {
    position: absolute;
    top: 0;
    left: 0;
    right: 0;
    bottom: 0;
    background: repeating-linear-gradient(
        0deg,
        transparent,
        transparent 2px,
        rgba(0, 0, 0, 0.15) 2px,
        rgba(0, 0, 0, 0.15) 4px
    );
    pointer-events: none;
    z-index: 1;
}

.display-scanlines::after {
    content: '';
    position: absolute;
    top: 0;
    left: 0;
    right: 0;
    height: 40px;
    background: linear-gradient(
        transparent 0%,
        rgba(0, 255, 100, 0.03) 50%,
        transparent 100%
    );
    animation: scanline 4s linear infinite;
}

@keyframes scanline {
    0% { top: -40px; }
    100% { top: 100%; }
}

.expression-display {
    font-family: var(--font-body);
    font-size: 14px;
    color: #666;
    margin-bottom: 8px;
    min-height: 20px;
    text-align: right;
    width: 100%;
    position: relative;
    z-index: 2;
}

.display {
    font-family: var(--font-display);
    font-size: 24px;
    color: var(--green);
    text-align: right;
    width: 100%;
    word-wrap: break-word;
    word-break: break-all;
    line-height: 1.4;
    position: relative;
    z-index: 2;
    text-shadow: 0 0 10px rgba(0, 200, 83, 0.5);
    transition: text-shadow 0.1s;
}

.display.glitch {
    animation: glitch 0.1s steps(2) 2;
}

@keyframes glitch {
    0% { text-shadow: 2px 0 var(--red), -2px 0 var(--blue); }
    50% { text-shadow: -2px 0 var(--red), 2px 0 var(--blue); }
    100% { text-shadow: 0 0 10px rgba(0, 200, 83, 0.5); }
}

.button-grid {
    display: grid;
    grid-template-columns: repeat(4, 1fr);
    gap: 10px;
}

.btn {
    font-family: var(--font-display);
    font-size: 12px;
    padding: 16px 8px;
    border: 3px solid var(--black);
    border-radius: 0;
    cursor: pointer;
    position: relative;
    top: 0;
    left: 0;
    box-shadow: 4px 4px 0px var(--black);
    transition: box-shadow 0.1s ease, top 0.1s ease, left 0.1s ease, transform 0.1s ease;
    outline: none;
    -webkit-tap-highlight-color: transparent;
    user-select: none;
}

.btn:hover {
    filter: brightness(1.1);
}

.btn:focus-visible {
    outline: 3px dashed var(--blue);
    outline-offset: 2px;
}

.btn:active,
.btn.pressed {
    top: 4px;
    left: 4px;
    box-shadow: 0px 0px 0px var(--black);
    transform: scale(0.97);
}

.btn-number {
    background-color: var(--white);
    color: var(--black);
    font-size: 14px;
}

.btn-number:hover {
    background-color: #f0f0f0;
}

.btn-operator {
    background-color: var(--red);
    color: var(--white);
    font-size: 14px;
}

.btn-operator:hover {
    background-color: #e6352b;
}

.btn-clear {
    background-color: var(--orange);
    color: var(--white);
    font-size: 10px;
}

.btn-clear:hover {
    background-color: #e68600;
}

.btn-back {
    background-color: var(--pink);
    color: var(--white);
    font-size: 16px;
}

.btn-back:hover {
    background-color: #e62883;
}

.btn-equals {
    background-color: var(--green);
    color: var(--white);
    font-size: 16px;
}

.btn-equals:hover {
    background-color: #00b34a;
}

.btn-memory {
    background-color: var(--yellow);
    color: var(--black);
    font-size: 8px;
    padding: 12px 6px;
}

.btn-memory:hover {
    background-color: #e6b800;
}

.btn-utility {
    background-color: var(--purple);
    color: var(--white);
    font-size: 12px;
}

.btn-utility:hover {
    background-color: #9b45c7;
}

.btn-decimal {
    background-color: var(--blue);
    color: var(--white);
    font-size: 16px;
}

.btn-decimal:hover {
    background-color: #006ee6;
}

@media (max-width: 480px) {
    .calculator {
        padding: 16px;
    }
    .display {
        font-size: 18px;
    }
    .btn {
        padding: 14px 6px;
        font-size: 10px;
    }
    .btn-number { font-size: 12px; }
    .btn-operator { font-size: 12px; }
    .btn-equals { font-size: 14px; }
    .btn-back { font-size: 14px; }
    .btn-memory { font-size: 7px; padding: 10px 4px; }
    .calc-label { font-size: 8px; }
    .button-grid { gap: 8px; }
}

@media (max-width: 360px) {
    .display { font-size: 14px; }
    .btn { padding: 12px 4px; font-size: 9px; }
    .btn-number { font-size: 11px; }
    .btn-operator { font-size: 11px; }
    .btn-memory { font-size: 6px; }
    .calc-label { font-size: 7px; }
    .button-grid { gap: 6px; }
}

@media (prefers-reduced-motion: reduce) {
    .btn {
        transition: none;
    }
    .display-scanlines::after {
        animation: none;
    }
    .display.glitch {
        animation: none;
    }
}

