import { useState, useCallback } from 'react';
import Display from './Display';
import Button from './Button';

interface CalculatorProps {
  addToHistory: (entry: string) => void;
}

export default function Calculator({ addToHistory }: CalculatorProps) {
  const [display, setDisplay] = useState('0');
  const [previousValue, setPreviousValue] = useState<string | null>(null);
  const [operator, setOperator] = useState<string | null>(null);
  const [waitingForOperand, setWaitingForOperand] = useState(false);
  const [expression, setExpression] = useState('');

  const inputDigit = useCallback(
    (digit: string) => {
      if (waitingForOperand) {
        setDisplay(digit);
        setWaitingForOperand(false);
      } else {
        setDisplay(display === '0' ? digit : display + digit);
      }
    },
    [display, waitingForOperand]
  );

  const inputDecimal = useCallback(() => {
    if (waitingForOperand) {
      setDisplay('0.');
      setWaitingForOperand(false);
      return;
    }
    if (!display.includes('.')) {
      setDisplay(display + '.');
    }
  }, [display, waitingForOperand]);

  const clear = useCallback(() => {
    setDisplay('0');
    setPreviousValue(null);
    setOperator(null);
    setWaitingForOperand(false);
    setExpression('');
  }, []);

  const toggleSign = useCallback(() => {
    const num = parseFloat(display);
    setDisplay(String(num * -1));
  }, [display]);

  const percentage = useCallback(() => {
    const num = parseFloat(display);
    setDisplay(String(num / 100));
  }, [display]);

  const squareRoot = useCallback(() => {
    const num = parseFloat(display);
    if (num < 0) {
      setDisplay('ERROR');
      return;
    }
    const result = Math.sqrt(num);
    addToHistory(`√(${num}) = ${parseFloat(result.toFixed(8))}`);
    setDisplay(String(parseFloat(result.toFixed(8))));
  }, [display, addToHistory]);

  const performOperation = useCallback(
    (nextOperator: string) => {
      const inputValue = parseFloat(display);

      if (previousValue !== null && operator && !waitingForOperand) {
        const result = calculate(parseFloat(previousValue), inputValue, operator);
        if (result === 'ERROR') {
          setDisplay('ERROR');
          setPreviousValue(null);
          setOperator(null);
          setExpression('');
          return;
        }
        const resultStr = parseFloat(result.toFixed(8)).toString();
        setDisplay(resultStr);
        setPreviousValue(resultStr);
        setExpression(`${resultStr} ${nextOperator}`);
      } else {
        setPreviousValue(display);
        setExpression(`${display} ${nextOperator}`);
      }

      setOperator(nextOperator);
      setWaitingForOperand(true);
    },
    [display, previousValue, operator, waitingForOperand]
  );

  const calculate = (a: number, b: number, op: string): string => {
    switch (op) {
      case '+': return (a + b).toString();
      case '-': return (a - b).toString();
      case '×': return (a * b).toString();
      case '÷':
        if (b === 0) return 'ERROR';
        return (a / b).toString();
      default: return b.toString();
    }
  };

  const handleEquals = useCallback(() => {
    if (previousValue === null || operator === null) return;

    const inputValue = parseFloat(display);
    const result = calculate(parseFloat(previousValue), inputValue, operator);

    if (result === 'ERROR') {
      setDisplay('ERROR');
      addToHistory(`${previousValue} ${operator} ${inputValue} = ERROR`);
    } else {
      const resultStr = parseFloat(result.toFixed(8)).toString();
      addToHistory(`${previousValue} ${operator} ${inputValue} = ${resultStr}`);
      setDisplay(resultStr);
    }

    setPreviousValue(null);
    setOperator(null);
    setWaitingForOperand(true);
    setExpression('');
  }, [display, previousValue, operator, addToHistory]);

  const handleSquare = useCallback(() => {
    const num = parseFloat(display);
    const result = num * num;
    addToHistory(`${num}² = ${parseFloat(result.toFixed(8))}`);
    setDisplay(String(parseFloat(result.toFixed(8))));
    setWaitingForOperand(true);
  }, [display, addToHistory]);

  const buttons: { label: string; action: () => void; span?: number; variant?: 'default' | 'operator' | 'equals' | 'clear' }[] = [
    { label: 'C', action: clear, variant: 'clear' },
    { label: '±', action: toggleSign },
    { label: '%', action: percentage },
    { label: '÷', action: () => performOperation('÷'), variant: 'operator' },
    { label: '7', action: () => inputDigit('7') },
    { label: '8', action: () => inputDigit('8') },
    { label: '9', action: () => inputDigit('9') },
    { label: '×', action: () => performOperation('×'), variant: 'operator' },
    { label: '4', action: () => inputDigit('4') },
    { label: '5', action: () => inputDigit('5') },
    { label: '6', action: () => inputDigit('6') },
    { label: '-', action: () => performOperation('-'), variant: 'operator' },
    { label: '1', action: () => inputDigit('1') },
    { label: '2', action: () => inputDigit('2') },
    { label: '3', action: () => inputDigit('3') },
    { label: '+', action: () => performOperation('+'), variant: 'operator' },
    { label: '√', action: squareRoot },
    { label: '0', action: () => inputDigit('0'), span: 2 },
    { label: '.', action: inputDecimal },
    { label: '=', action: handleEquals, variant: 'equals' },
  ];

  return (
    <div className="border-4 border-black bg-white shadow-[8px_8px_0px_0px_rgba(0,0,0,1)] overflow-hidden">
      <Display value={display} expression={expression} />
      <div className="grid grid-cols-4 gap-0">
        {buttons.map((btn, i) => (
          <Button
            key={i}
            label={btn.label}
            onClick={btn.action}
            span={btn.span}
            variant={btn.variant}
          />
        ))}
      </div>
    </div>
  );
}

