import { useState } from 'react';

interface ButtonProps {
  label: string;
  onClick: () => void;
  span?: number;
  variant?: 'default' | 'operator' | 'equals' | 'clear';
}

export default function Button({ label, onClick, span, variant = 'default' }: ButtonProps) {
  const [pressed, setPressed] = useState(false);

  const handleClick = () => {
    setPressed(true);
    onClick();
    setTimeout(() => setPressed(false), 150);
  };

  const baseClasses =
    'relative border-2 border-black font-space-mono font-bold text-xl py-4 transition-all duration-100 cursor-pointer select-none focus:outline-none focus-visible:ring-4 focus-visible:ring-yellow-300 focus-visible:ring-offset-2';

  const variantClasses = {
    default: 'bg-white text-black hover:bg-gray-100 active:bg-gray-200',
    operator: 'bg-black text-white hover:bg-gray-800 active:bg-gray-700',
    equals: 'bg-yellow-300 text-black hover:bg-yellow-400 active:bg-yellow-500',
    clear: 'bg-red-500 text-white hover:bg-red-600 active:bg-red-700',
  };

  const pressedTransform = pressed ? 'translate-x-[3px] translate-y-[3px] shadow-none' : 'shadow-[4px_4px_0px_0px_rgba(0,0,0,1)]';

  return (
    <button
      className={`${baseClasses} ${variantClasses[variant]} ${pressedTransform} ${span === 2 ? 'col-span-2' : ''}`}
      onClick={handleClick}
      aria-label={label}
    >
      {label}
    </button>
  );
}
