interface DisplayProps {
  value: string;
  expression: string;
}

export default function Display({ value, expression }: DisplayProps) {
  const formatDisplay = (val: string): string => {
    if (val === 'ERROR') return val;
    const num = parseFloat(val);
    if (isNaN(num)) return val;
    if (val.endsWith('.')) return val;
    if (val.includes('.') && val.endsWith('0') && !waitingForDot(val)) return val;
    if (Math.abs(num) >= 1e12) return num.toExponential(4);
    if (val.length > 12) {
      return parseFloat(num.toPrecision(10)).toString();
    }
    return val;
  };

  const waitingForDot = (val: string): boolean => {
    return val.endsWith('.');
  };

  return (
    <div className="bg-black p-5 border-b-4 border-black">
      <div className="text-right font-space-mono min-h-[60px] flex flex-col justify-end">
        {expression && (
          <div className="text-white/40 text-sm h-5 truncate">
            {expression}
          </div>
        )}
        <div
          className="text-white font-bold tracking-tight truncate"
          style={{ fontSize: value.length > 8 ? '1.5rem' : value.length > 6 ? '2rem' : '2.5rem' }}
        >
          {formatDisplay(value)}
        </div>
      </div>
    </div>
  );
}

