/* ============================================
   MERIDIAN — Real-Time E-Commerce Dashboard
   Interactive JavaScript
   ============================================ */

(function() {
  'use strict';

  // --- State ---
  const state = {
    chartRange: '24h',
    revenueData: [],
    donutData: [38, 27, 21, 14],
    feedItems: [],
    maxFeedItems: 20,
    counters: {}
  };

  // --- Product Data ---
  const products = [
    { name: 'MacBook Pro 16"', category: 'Electronics', price: 2499, stock: 45, image: 'https://images.unsplash.com/photo-1517336714731-489689fd1ca8?w=400&h=400&fit=crop' },
    { name: 'Sony WH-1000XM5', category: 'Electronics', price: 349, stock: 120, image: 'https://images.unsplash.com/photo-1618366712010-f4ae9c647dcb?w=400&h=400&fit=crop' },
    { name: 'Nike Air Max 90', category: 'Apparel', price: 129, stock: 8, image: 'https://images.unsplash.com/photo-1542291026-7eec264c27ff?w=400&h=400&fit=crop' },
    { name: 'Herman Miller Aeron', category: 'Furniture', price: 1395, stock: 22, image: 'https://images.unsplash.com/photo-1580480055273-228ff5388ef8?w=400&h=400&fit=crop' },
    { name: 'iPad Pro 12.9"', category: 'Electronics', price: 1099, stock: 3, image: 'https://images.unsplash.com/photo-1544244015-0df4b3ffc6b0?w=400&h=400&fit=crop' },
    { name: 'Levi\'s 501 Original', category: 'Apparel', price: 69, stock: 200, image: 'https://images.unsplash.com/photo-1542272604-787c3835535d?w=400&h=400&fit=crop' },
  ];

  // --- Names for Feed ---
  const customerNames = ['Sarah Chen', 'Marcus Johnson', 'Emily Rodriguez', 'David Park', 'Lisa Thompson', 'James Wilson', 'Aisha Patel', 'Robert Kim', 'Olivia Brown', 'Michael Davis', 'Sophia Martinez', 'Daniel Lee', 'Isabella Garcia', 'Ethan Moore', 'Charlotte Taylor'];
  const cities = ['New York', 'Los Angeles', 'Chicago', 'Houston', 'Phoenix', 'San Francisco', 'Seattle', 'Denver', 'Boston', 'Miami'];

  // --- Utility Functions ---
  function randomInt(min, max) {
    return Math.floor(Math.random() * (max - min + 1)) + min;
  }

  function randomFloat(min, max, decimals = 2) {
    return parseFloat((Math.random() * (max - min) + min).toFixed(decimals));
  }

  function formatCurrency(val) {
    return new Intl.NumberFormat('en-US', { style: 'currency', currency: 'USD', minimumFractionDigits: 0, maximumFractionDigits: 0 }).format(val);
  }

  function formatNumber(val) {
    return new Intl.NumberFormat('en-US').format(val);
  }

  function timeAgo(seconds) {
    if (seconds < 60) return `${seconds}s ago`;
    if (seconds < 3600) return `${Math.floor(seconds / 60)}m ago`;
    return `${Math.floor(seconds / 3600)}h ago`;
  }

  // --- Counter Animation ---
  function animateCounter(el) {
    const target = parseFloat(el.dataset.target);
    const prefix = el.dataset.prefix || '';
    const suffix = el.dataset.suffix || '';
    const format = el.dataset.format || 'number';
    const duration = 2000;
    const startTime = performance.now();
    const startVal = 0;

    function ease(t) {
      return t < 0.5 ? 4 * t * t * t : 1 - Math.pow(-2 * t + 2, 3) / 2;
    }

    function update(currentTime) {
      const elapsed = currentTime - startTime;
      const progress = Math.min(elapsed / duration, 1);
      const easedProgress = ease(progress);
      const current = startVal + (target - startVal) * easedProgress;

      let display;
      if (format === 'currency') {
        display = prefix + formatCurrency(current) + suffix;
      } else if (format === 'decimal') {
        display = current.toFixed(2) + suffix;
      } else {
        display = prefix + formatNumber(Math.round(current)) + suffix;
      }

      el.textContent = display;

      if (progress < 1) {
        requestAnimationFrame(update);
      }
    }

    requestAnimationFrame(update);
  }

  // --- Initialize Counters ---
  function initCounters() {
    document.querySelectorAll('.kpi-value').forEach(el => {
      animateCounter(el);
    });
  }

  // --- Revenue Chart (Canvas) ---
  function generateRevenueData(range) {
    const points = range === '24h' ? 24 : range === '7d' ? 7 : 30;
    const baseRevenue = range === '24h' ? 8000 : range === '7d' ? 50000 : 200000;
    const data = [];
    for (let i = 0; i < points; i++) {
      const trend = i / points;
      const noise = (Math.random() - 0.5) * baseRevenue * 0.3;
      const val = baseRevenue * (0.6 + trend * 0.4) + noise;
      data.push(Math.max(0, val));
    }
    return data;
  }

  function drawRevenueChart() {
    const canvas = document.getElementById('revenueChart');
    if (!canvas) return;

    const container = canvas.parentElement;
    const dpr = window.devicePixelRatio || 1;
    const rect = container.getBoundingClientRect();

    canvas.width = rect.width * dpr;
    canvas.height = rect.height * dpr;
    canvas.style.width = rect.width + 'px';
    canvas.style.height = rect.height + 'px';

    const ctx = canvas.getContext('2d');
    ctx.scale(dpr, dpr);

    const w = rect.width;
    const h = rect.height;
    const padding = { top: 20, right: 20, bottom: 30, left: 50 };
    const chartW = w - padding.left - padding.right;
    const chartH = h - padding.top - padding.bottom;

    const data = state.revenueData;
    const maxVal = Math.max(...data) * 1.1;
    const minVal = 0;

    // Clear
    ctx.clearRect(0, 0, w, h);

    // Grid lines
    ctx.strokeStyle = 'rgba(148, 163, 184, 0.06)';
    ctx.lineWidth = 1;
    const gridLines = 5;
    for (let i = 0; i <= gridLines; i++) {
      const y = padding.top + (chartH / gridLines) * i;
      ctx.beginPath();
      ctx.moveTo(padding.left, y);
      ctx.lineTo(w - padding.right, y);
      ctx.stroke();

      // Y-axis labels
      const val = maxVal - (maxVal / gridLines) * i;
      ctx.fillStyle = '#64748B';
      ctx.font = '11px Inter';
      ctx.textAlign = 'right';
      ctx.fillText(formatCurrency(val), padding.left - 8, y + 4);
    }

    // X-axis labels
    const labelCount = Math.min(data.length, 8);
    ctx.textAlign = 'center';
    for (let i = 0; i < labelCount; i++) {
      const idx = Math.floor((i / (labelCount - 1)) * (data.length - 1));
      const x = padding.left + (idx / (data.length - 1)) * chartW;
      const label = state.chartRange === '24h' ? `${idx}:00` : 
                    state.chartRange === '7d' ? `Day ${idx + 1}` : 
                    `${Math.floor(idx / 7) + 1}w`;
      ctx.fillText(label, x, h - 8);
    }

    // Area gradient
    const gradient = ctx.createLinearGradient(0, padding.top, 0, h - padding.bottom);
    gradient.addColorStop(0, 'rgba(56, 189, 248, 0.2)');
    gradient.addColorStop(0.5, 'rgba(56, 189, 248, 0.05)');
    gradient.addColorStop(1, 'rgba(56, 189, 248, 0)');

    // Draw area
    ctx.beginPath();
    ctx.moveTo(padding.left, h - padding.bottom);
    data.forEach((val, i) => {
      const x = padding.left + (i / (data.length - 1)) * chartW;
      const y = padding.top + chartH - ((val - minVal) / (maxVal - minVal)) * chartH;
      if (i === 0) ctx.lineTo(x, y);
      else {
        const prevX = padding.left + ((i - 1) / (data.length - 1)) * chartW;
        const prevY = padding.top + chartH - ((data[i - 1] - minVal) / (maxVal - minVal)) * chartH;
        const cpx = (prevX + x) / 2;
        ctx.bezierCurveTo(cpx, prevY, cpx, y, x, y);
      }
    });
    ctx.lineTo(padding.left + chartW, h - padding.bottom);
    ctx.closePath();
    ctx.fillStyle = gradient;
    ctx.fill();

    // Draw line
    ctx.beginPath();
    data.forEach((val, i) => {
      const x = padding.left + (i / (data.length - 1)) * chartW;
      const y = padding.top + chartH - ((val - minVal) / (maxVal - minVal)) * chartH;
      if (i === 0) ctx.moveTo(x, y);
      else {
        const prevX = padding.left + ((i - 1) / (data.length - 1)) * chartW;
        const prevY = padding.top + chartH - ((data[i - 1] - minVal) / (maxVal - minVal)) * chartH;
        const cpx = (prevX + x) / 2;
        ctx.bezierCurveTo(cpx, prevY, cpx, y, x, y);
      }
    });
    ctx.strokeStyle = '#38BDF8';
    ctx.lineWidth = 2.5;
    ctx.lineCap = 'round';
    ctx.lineJoin = 'round';
    ctx.stroke();

    // Glow dot at last point
    if (data.length > 0) {
      const lastX = padding.left + chartW;
      const lastY = padding.top + chartH - ((data[data.length - 1] - minVal) / (maxVal - minVal)) * chartH;

      // Glow
      const glowGrad = ctx.createRadialGradient(lastX, lastY, 0, lastX, lastY, 12);
      glowGrad.addColorStop(0, 'rgba(56, 189, 248, 0.4)');
      glowGrad.addColorStop(1, 'rgba(56, 189, 248, 0)');
      ctx.fillStyle = glowGrad;
      ctx.beginPath();
      ctx.arc(lastX, lastY, 12, 0, Math.PI * 2);
      ctx.fill();

      // Dot
      ctx.beginPath();
      ctx.arc(lastX, lastY, 4, 0, Math.PI * 2);
      ctx.fillStyle = '#38BDF8';
      ctx.fill();
      ctx.strokeStyle = '#0F172A';
      ctx.lineWidth = 2;
      ctx.stroke();
    }
  }

  // --- Donut Chart ---
  function drawDonutChart() {
    const canvas = document.getElementById('donutChart');
    if (!canvas) return;

    const dpr = window.devicePixelRatio || 1;
    const size = 200;
    canvas.width = size * dpr;
    canvas.height = size * dpr;
    canvas.style.width = size + 'px';
    canvas.style.height = size + 'px';

    const ctx = canvas.getContext('2d');
    ctx.scale(dpr, dpr);

    const cx = size / 2;
    const cy = size / 2;
    const outerR = 80;
    const innerR = 55;

    const colors = ['#38BDF8', '#818CF8', '#34D399', '#F43F5E'];
    const data = state.donutData;
    const total = data.reduce((a, b) => a + b, 0);

    let startAngle = -Math.PI / 2;

    data.forEach((val, i) => {
      const sliceAngle = (val / total) * Math.PI * 2;
      const endAngle = startAngle + sliceAngle;

      ctx.beginPath();
      ctx.arc(cx, cy, outerR, startAngle, endAngle);
      ctx.arc(cx, cy, innerR, endAngle, startAngle, true);
      ctx.closePath();
      ctx.fillStyle = colors[i];
      ctx.fill();

      // Gap between segments
      ctx.strokeStyle = '#1E293B';
      ctx.lineWidth = 3;
      ctx.stroke();

      startAngle = endAngle;
    });

    // Glow effect on hover segment (subtle ambient)
    ctx.beginPath();
    ctx.arc(cx, cy, outerR + 4, 0, Math.PI * 2);
    ctx.strokeStyle = 'rgba(56, 189, 248, 0.1)';
    ctx.lineWidth = 8;
    ctx.stroke();
  }

  // --- Product Grid ---
  function renderProducts() {
    const grid = document.getElementById('productGrid');
    if (!grid) return;

    grid.innerHTML = products.map(p => {
      const stockClass = p.stock > 50 ? 'high' : p.stock > 10 ? 'medium' : 'low';
      return `
        <div class="product-item">
          <div class="product-image">
            <img src="${p.image}" alt="${p.name}" loading="lazy" />
          </div>
          <div class="product-name">${p.name}</div>
          <div class="product-category">${p.category}</div>
          <div class="product-meta">
            <span class="product-price">${formatCurrency(p.price)}</span>
            <span class="product-stock ${stockClass}">${p.stock} left</span>
          </div>
        </div>
      `;
    }).join('');
  }

  // --- Live Feed ---
  function createFeedItem() {
    const types = ['sale', 'sale', 'sale', 'new', 'refund'];
    const type = types[randomInt(0, types.length - 1)];
    const name = customerNames[randomInt(0, customerNames.length - 1)];
    const city = cities[randomInt(0, cities.length - 1)];
    const product = products[randomInt(0, products.length - 1)];

    let icon, title, subtitle, amount, amountClass;

    if (type === 'sale') {
      icon = '✓';
      title = `New order from ${name}`;
      subtitle = `${city} · ${product.name}`;
      amount = `+${formatCurrency(product.price * randomInt(1, 3))}`;
      amountClass = 'positive';
    } else if (type === 'new') {
      icon = '★';
      title = `${name} registered`;
      subtitle = `${city} · New customer`;
      amount = 'New';
      amountClass = 'positive';
    } else {
      icon = '↩';
      title = `Refund processed`;
      subtitle = `${name} · ${product.name}`;
      amount = `-${formatCurrency(product.price)}`;
      amountClass = 'negative';
    }

    return {
      icon,
      type,
      title,
      subtitle,
      amount,
      amountClass,
      time: 'Just now',
      timestamp: Date.now()
    };
  }

  function addFeedItem() {
    const list = document.getElementById('feedList');
    if (!list) return;

    const item = createFeedItem();
    state.feedItems.unshift(item);

    if (state.feedItems.length > state.maxFeedItems) {
      state.feedItems.pop();
    }

    const html = `
      <div class="feed-item">
        <div class="feed-icon ${item.type}">${item.icon}</div>
        <div class="feed-content">
          <div class="feed-title">${item.title}</div>
          <div class="feed-subtitle">${item.subtitle}</div>
        </div>
        <div>
          <div class="feed-amount ${item.amountClass}">${item.amount}</div>
          <div class="feed-time">${item.time}</div>
        </div>
      </div>
    `;

    list.insertAdjacentHTML('afterbegin', html);

    // Remove last if too many
    const items = list.querySelectorAll('.feed-item');
    if (items.length > state.maxFeedItems) {
      items[items.length - 1].remove();
    }
  }

  function renderInitialFeed() {
    const list = document.getElementById('feedList');
    if (!list) return;

    let html = '';
    for (let i = 0; i < 8; i++) {
      const item = createFeedItem();
      const secondsAgo = randomInt(5, 300);
      item.time = timeAgo(secondsAgo);
      state.feedItems.push(item);
      html += `
        <div class="feed-item">
          <div class="feed-icon ${item.type}">${item.icon}</div>
          <div class="feed-content">
            <div class="feed-title">${item.title}</div>
            <div class="feed-subtitle">${item.subtitle}</div>
          </div>
          <div>
            <div class="feed-amount ${item.amountClass}">${item.amount}</div>
            <div class="feed-time">${item.time}</div>
          </div>
        </div>
      `;
    }
    list.innerHTML = html;
  }

  // --- Chart Range Switching ---
  function switchChartRange(range) {
    state.chartRange = range;
    state.revenueData = generateRevenueData(range);
    drawRevenueChart();

    document.querySelectorAll('.chart-tab').forEach(tab => {
      tab.classList.toggle('active', tab.dataset.range === range);
    });
  }

  // --- Real-time Data Updates ---
  function updateLiveData() {
    // Update revenue chart with new data point
    if (state.revenueData.length > 0) {
      const lastVal = state.revenueData[state.revenueData.length - 1];
      const newVal = lastVal * (1 + (Math.random() - 0.48) * 0.05);
      state.revenueData[state.revenueData.length - 1] = Math.max(0, newVal);
      drawRevenueChart();
    }

    // Update KPI values slightly
    const kpiCards = document.querySelectorAll('.kpi-value');
    kpiCards.forEach(el => {
      const target = parseFloat(el.dataset.target);
      const variation = target * (1 + (Math.random() - 0.5) * 0.01);
      const format = el.dataset.format || 'number';
      const prefix = el.dataset.prefix || '';
      const suffix = el.dataset.suffix || '';

      if (format === 'currency') {
        el.textContent = prefix + formatCurrency(variation) + suffix;
      } else if (format === 'decimal') {
        el.textContent = variation.toFixed(2) + suffix;
      } else {
        el.textContent = prefix + formatNumber(Math.round(variation)) + suffix;
      }
    });
  }

  // --- Sidebar Toggle ---
  function initSidebar() {
    const toggle = document.getElementById('menuToggle');
    const sidebar = document.getElementById('sidebar');
    const overlay = document.getElementById('sidebarOverlay');

    if (!toggle || !sidebar) return;

    toggle.addEventListener('click', () => {
      sidebar.classList.toggle('open');
      overlay.classList.toggle('open');
    });

    overlay.addEventListener('click', () => {
      sidebar.classList.remove('open');
      overlay.classList.remove('open');
    });
  }

  // --- Chart Tab Handlers ---
  function initChartTabs() {
    document.querySelectorAll('.chart-tab').forEach(tab => {
      tab.addEventListener('click', () => {
        switchChartRange(tab.dataset.range);
      });
    });
  }

  // --- Navigation Handler ---
  function initNavigation() {
    document.querySelectorAll('.nav-item').forEach(item => {
      item.addEventListener('click', (e) => {
        e.preventDefault();
        document.querySelectorAll('.nav-item').forEach(n => n.classList.remove('active'));
        item.classList.add('active');

        // Close sidebar on mobile
        const sidebar = document.getElementById('sidebar');
        const overlay = document.getElementById('sidebarOverlay');
        if (sidebar) sidebar.classList.remove('open');
        if (overlay) overlay.classList.remove('open');
      });
    });
  }

  // --- Resize Handler ---
  function initResize() {
    let timeout;
    window.addEventListener('resize', () => {
      clearTimeout(timeout);
      timeout = setTimeout(() => {
        drawRevenueChart();
        drawDonutChart();
      }, 150);
    });
  }

  // --- Keyboard Accessibility ---
  function initKeyboard() {
    document.addEventListener('keydown', (e) => {
      if (e.key === 'Escape') {
        const sidebar = document.getElementById('sidebar');
        const overlay = document.getElementById('sidebarOverlay');
        if (sidebar && sidebar.classList.contains('open')) {
          sidebar.classList.remove('open');
          overlay.classList.remove('open');
        }
      }
    });
  }

  // --- Initialization ---
  function init() {
    // Generate initial data
    state.revenueData = generateRevenueData('24h');

    // Render UI
    initCounters();
    drawRevenueChart();
    drawDonutChart();
    renderProducts();
    renderInitialFeed();

    // Event handlers
    initSidebar();
    initChartTabs();
    initNavigation();
    initResize();
    initKeyboard();

    // Real-time updates
    setInterval(addFeedItem, 3000);
    setInterval(updateLiveData, 5000);
  }

  // Start when DOM is ready
  if (document.readyState === 'loading') {
    document.addEventListener('DOMContentLoaded', init);
  } else {
    init();
  }

})();

