    await saveDB();
  },
  findUserByUsername: (username) => db.users.find(u => u.username === username),

  getProducts: () => db.products,
  getProductById: (id) => db.products.find(p => p.id === parseInt(id)),
  addProduct: async (product) => {
    product.id = db.nextProduct++;
    db.products.push(product);
    await saveDB();
    return product;
