const express = require('express');
const bcrypt = require('bcrypt');
const db = require('../models/db');

const router = express.Router();

router.post('/login', async (req, res) => {
  const { username, password } = req.body;

  if (!username || !password) {
    return res.status(400).json({ message: 'Username and password are required.' });
  }

  const user = db.findUserByUsername(username);

  if (!user) {
    return res.status(401).json({ message: 'Invalid credentials.' });
  }

  const isPasswordValid = await bcrypt.compare(password, user.password);

  if (!isPasswordValid) {
    return res.status(401).json({ message: 'Invalid credentials.' });
  }

  // Set session variables
  req.session.userId = user.id;
  req.session.username = user.username;
  req.session.role = user.role;

  res.status(200).json({ message: 'Login successful', user: { id: user.id, username: user.username, role: user.role } });
});

router.post('/logout', (req, res) => {
  req.session.destroy(err => {
    if (err) {
      return res.status(500).json({ message: 'Could not log out, please try again.' });
    }
    res.clearCookie('connect.sid'); // Clear the session cookie
    res.status(200).json({ message: 'Logout successful' });
  });
});

router.get('/status', (req, res) => {
  if (req.session && req.session.userId) {
    res.status(200).json({ isAuthenticated: true, user: { id: req.session.userId, username: req.session.username, role: req.session.role } });
  } else {
    res.status(200).json({ isAuthenticated: false });
  }
});

module.exports = router;

