const { body, param, validationResult } = require('express-validator');

const handleValidationErrors = (req, res, next) => {
  const errors = validationResult(req);
  if (!errors.isEmpty()) {
    return res.status(400).json({ errors: errors.array() });
  }
  next();
};

const productValidation = [
  body('name').trim().isLength({ min: 3, max: 100 }).withMessage('Product name must be between 3 and 100 characters.'),
  body('category').trim().isIn(['Electronics', 'Clothing', 'Accessories', 'Home & Living', 'Furniture', 'Apparel']).withMessage('Invalid product category.'),
  body('price').isFloat({ min: 0.01 }).withMessage('Price must be a positive number.'),
  body('stock').isInt({ min: 0 }).withMessage('Stock must be a non-negative integer.'),
  body('image').optional().isURL().withMessage('Image must be a valid URL.'),
  body('description').optional().trim().isLength({ max: 500 }).withMessage('Description cannot exceed 500 characters.'),
  handleValidationErrors
];

const orderValidation = [
  body('customer').trim().isLength({ min: 2, max: 100 }).withMessage('Customer name must be between 2 and 100 characters.'),
  body('product').trim().isLength({ min: 2, max: 100 }).withMessage('Product name must be between 2 and 100 characters.'),
  body('amount').isFloat({ min: 0.01 }).withMessage('Amount must be a positive number.'),
  body('status').trim().isIn(['pending', 'processing', 'shipped', 'delivered']).withMessage('Invalid order status.'),
  body('date').isISO8601().withMessage('Date must be a valid ISO 8601 date string.'),
  handleValidationErrors
];

const customerValidation = [
  body('name').trim().isLength({ min: 2, max: 100 }).withMessage('Customer name must be between 2 and 100 characters.'),
  body('email').isEmail().withMessage('Invalid email address.'),
  body('totalOrders').isInt({ min: 0 }).withMessage('Total orders must be a non-negative integer.'),
  body('totalSpent').isFloat({ min: 0 }).withMessage('Total spent must be a non-negative number.'),
  body('lastOrder').isISO8601().withMessage('Last order date must be a valid ISO 8601 date string.'),
  handleValidationErrors
];

const idParamValidation = [
  param('id').isInt({ min: 1 }).withMessage('ID must be a positive integer.'),
  handleValidationErrors
];

module.exports = {
  productValidation,
  orderValidation,
  customerValidation,
  idParamValidation
};

