  --surface-light: #2a3545;
  --border: #2a3545;
  --text: #C5C6C7;
  --text-bright: #f0f0f2;
  --text-muted: #6b7280;
  --accent: #66FCF1;
  --accent-dark: #45A29E;
  --gold: #FFD700;
  --danger: #ef4444;
  --success: #22c55e;
  --radius: 12px;
  --radius-lg: 20px;
  --shadow: 0 4px 24px rgba(0,0,0,0.4);
  --shadow-lg: 0 8px 48px rgba(0,0,0,0.6);
  --transition: 0.3s cubic-bezier(0.4, 0, 0.2, 1);
  --font-display: 'Playfair Display', Georgia, serif;
  --font-body: 'Inter', -apple-system, sans-serif;
}

*, *::before, *::after {
  margin: 0;
  padding: 0;
  box-sizing: border-box;
}

html {
  scroll-behavior: smooth;
  font-size: 16px;
}

body {
  font-family: var(--font-body);
  background: var(--bg);
  color: var(--text);
  line-height: 1.6;
  overflow-x: hidden;
  -webkit-font-smoothing: antialiased;
}

a { color: inherit; text-decoration: none; }
button { cursor: pointer; font-family: inherit; border: none; background: none; color: inherit; }
img { max-width: 100%; display: block; }

/* Scrollbar */
::-webkit-scrollbar { width: 6px; }
::-webkit-scrollbar-track { background: var(--bg); }
::-webkit-scrollbar-thumb { background: var(--surface-light); border-radius: 3px; }
::-webkit-scrollbar-thumb:hover { background: var(--accent-dark); }

/* Focus States */
:focus-visible {
  outline: 2px solid var(--accent);
  outline-offset: 2px;
  border-radius: 4px;
}

/* ============================================
   NAVBAR
   ============================================ */
.navbar {
  position: fixed;
  top: 0;
  left: 0;
  right: 0;
  z-index: 100;
  background: rgba(11, 12, 16, 0.85);
  backdrop-filter: blur(20px);
  border-bottom: 1px solid rgba(102, 252, 241, 0.08);
  transition: var(--transition);
}

.navbar.scrolled {
  background: rgba(11, 12, 16, 0.95);
  box-shadow: 0 4px 24px rgba(0,0,0,0.4);
}

.nav-inner {
  max-width: 1400px;
  margin: 0 auto;
  padding: 0 24px;
  height: 64px;
  display: flex;
  align-items: center;
  justify-content: space-between;
  gap: 32px;
}

.nav-brand {
  display: flex;
  align-items: center;
  gap: 10px;
}

.brand-mark {
  font-size: 24px;
  color: var(--accent);
  text-shadow: 0 0 20px rgba(102, 252, 241, 0.5);
}

.brand-name {
  font-family: var(--font-display);
  font-size: 22px;
  font-weight: 700;
  letter-spacing: 4px;
  color: var(--text-bright);
}

.nav-links {
  display: flex;
  gap: 8px;
}

.nav-link {
  padding: 8px 16px;
  font-size: 14px;
  font-weight: 500;
  color: var(--text-muted);
  border-radius: 8px;
  transition: var(--transition);
}

.nav-link:hover, .nav-link.active {
  color: var(--text-bright);
  background: rgba(102, 252, 241, 0.08);
}

.nav-actions {
  display: flex;
  align-items: center;
  gap: 8px;
}

.nav-icon-btn {
  width: 40px;
  height: 40px;
  display: flex;
  align-items: center;
  justify-content: center;
  border-radius: 10px;
  color: var(--text-muted);
  transition: var(--transition);
  position: relative;
}

.nav-icon-btn:hover {
  color: var(--text-bright);
  background: rgba(102, 252, 241, 0.08);
}

.cart-badge {
  position: absolute;
  top: 4px;
  right: 4px;
  width: 18px;
  height: 18px;
  background: var(--accent);
  color: var(--bg);
  font-size: 10px;
  font-weight: 700;
  border-radius: 50%;
  display: flex;
  align-items: center;
  justify-content: center;
  transform: scale(0);
  transition: transform 0.3s cubic-bezier(0.34, 1.56, 0.64, 1);
}

.cart-badge.visible {
  transform: scale(1);
}

/* ============================================
   HERO
   ============================================ */
.hero {
  position: relative;
  min-height: 100vh;
  display: flex;
  align-items: center;
  padding: 100px 24px 60px;
  overflow: hidden;
}

.hero-bg {
  position: absolute;
  inset: 0;
  pointer-events: none;
}

.hero-glow {
  position: absolute;
  border-radius: 50%;
  filter: blur(120px);
  opacity: 0.15;
}

.hero-glow-1 {
  width: 600px;
  height: 600px;
  background: var(--accent);
  top: -200px;
  right: -100px;
  animation: floatGlow 8s ease-in-out infinite;
}

.hero-glow-2 {
  width: 400px;
  height: 400px;
  background: var(--gold);
  bottom: -100px;
  left: -100px;
  animation: floatGlow 10s ease-in-out infinite reverse;
}

.hero-grid {
  position: absolute;
  inset: 0;
  background-image:
    linear-gradient(rgba(102, 252, 241, 0.03) 1px, transparent 1px),
    linear-gradient(90deg, rgba(102, 252, 241, 0.03) 1px, transparent 1px);
  background-size: 60px 60px;
}

@keyframes floatGlow {
  0%, 100% { transform: translate(0, 0) scale(1); }
  50% { transform: translate(30px, -30px) scale(1.1); }
}

.hero-content {
  max-width: 1400px;
  margin: 0 auto;
  width: 100%;
  display: grid;
  grid-template-columns: 1fr 1fr;
  gap: 60px;
  align-items: center;
  position: relative;
  z-index: 2;
}

.hero-badge {
  display: inline-flex;
  align-items: center;
  gap: 8px;
  padding: 8px 16px;
  background: rgba(102, 252, 241, 0.08);
  border: 1px solid rgba(102, 252, 241, 0.2);
  border-radius: 100px;
  font-size: 13px;
  font-weight: 500;
  color: var(--accent);
  margin-bottom: 24px;
  animation: fadeInUp 0.6s ease-out;
}

.live-dot {
  width: 8px;
  height: 8px;
  background: var(--success);
  border-radius: 50%;
  animation: pulse 2s ease-in-out infinite;
}

@keyframes pulse {
  0%, 100% { box-shadow: 0 0 0 0 rgba(34, 197, 94, 0.4); }
  50% { box-shadow: 0 0 0 8px rgba(34, 197, 94, 0); }
}

.hero-title {
  font-family: var(--font-display);
  font-size: clamp(40px, 6vw, 72px);
  font-weight: 800;
  line-height: 1.1;
  color: var(--text-bright);
  margin-bottom: 24px;
  animation: fadeInUp 0.6s ease-out 0.1s both;
}

.hero-line {
  display: block;
}

.hero-line-accent {
  background: linear-gradient(135deg, var(--accent), var(--gold));
  -webkit-background-clip: text;
  -webkit-text-fill-color: transparent;
  background-clip: text;
}

.hero-subtitle {
  font-size: 18px;
  line-height: 1.7;
  color: var(--text-muted);
  max-width: 520px;
  margin-bottom: 36px;
  animation: fadeInUp 0.6s ease-out 0.2s both;
}

.hero-cta {
  display: flex;
  gap: 16px;
  flex-wrap: wrap;
  animation: fadeInUp 0.6s ease-out 0.3s both;
}

@keyframes fadeInUp {
  from { opacity: 0; transform: translateY(20px); }
  to { opacity: 1; transform: translateY(0); }
}

/* Buttons */
.btn {
  display: inline-flex;
  align-items: center;
  gap: 8px;
  padding: 14px 28px;
  font-size: 15px;
  font-weight: 600;
  border-radius: 12px;
  transition: var(--transition);
  white-space: nowrap;
}

.btn-primary {
  background: linear-gradient(135deg, var(--accent), var(--accent-dark));
  color: var(--bg);
  box-shadow: 0 4px 20px rgba(102, 252, 241, 0.3);
}

.btn-primary:hover {
  transform: translateY(-2px);
  box-shadow: 0 8px 32px rgba(102, 252, 241, 0.4);
}

.btn-ghost {
  background: rgba(102, 252, 241, 0.06);
  border: 1px solid rgba(102, 252, 241, 0.2);
  color: var(--text-bright);
}

.btn-ghost:hover {
  background: rgba(102, 252, 241, 0.12);
  border-color: rgba(102, 252, 241, 0.4);
}

.btn-full { width: 100%; justify-content: center; }

/* Hero Visual */
.hero-visual {
  position: relative;
  display: flex;
  flex-direction: column;
  align-items: center;
  animation: fadeInUp 0.8s ease-out 0.3s both;
}

.hero-product-ring {
  position: relative;
  width: 380px;
  height: 380px;
  display: flex;
  align-items: center;
  justify-content: center;
}

.pulse-ring {
  position: absolute;
  inset: 0;
  border: 2px solid rgba(102, 252, 241, 0.2);
  border-radius: 50%;
  animation: pulseRing 3s ease-out infinite;
}

.pulse-ring-2 { animation-delay: 1s; }
.pulse-ring-3 { animation-delay: 2s; }

@keyframes pulseRing {
  0% { transform: scale(0.8); opacity: 1; }
  100% { transform: scale(1.4); opacity: 0; }
}

.hero-product-image {
  position: relative;
  width: 280px;
  height: 280px;
  border-radius: 50%;
  overflow: hidden;
  box-shadow: 0 0 60px rgba(102, 252, 241, 0.15), var(--shadow-lg);
  border: 3px solid rgba(102, 252, 241, 0.15);
}

.hero-product-image img {
  width: 100%;
  height: 100%;
  object-fit: cover;
  transition: transform 0.6s ease;
}

.hero-product-image:hover img {
  transform: scale(1.05);
}

.product-info-overlay {
  position: absolute;
  bottom: -1px;
  left: 0;
  right: 0;
  padding: 20px;
  background: linear-gradient(transparent, rgba(11, 12, 16, 0.9));
  display: flex;
  justify-content: space-between;
  align-items: flex-end;
}

.product-name {
  font-family: var(--font-display);
  font-size: 18px;
  font-weight: 600;
  color: var(--text-bright);
}

.product-price {
  font-size: 20px;
  font-weight: 700;
  color: var(--gold);
}

.hero-stats {
  display: flex;
  gap: 32px;
  margin-top: 32px;
}

.hero-stat {
  text-align: center;
}

.stat-value {
  display: block;
  font-family: var(--font-display);
  font-size: 24px;
  font-weight: 700;
  color: var(--text-bright);
}

.stat-label {
  font-size: 12px;
  color: var(--text-muted);
  text-transform: uppercase;
  letter-spacing: 1px;
}

/* ============================================
   TICKER
   ============================================ */
.ticker {
  background: var(--surface);
  border-top: 1px solid var(--border);
  border-bottom: 1px solid var(--border);
  padding: 12px 0;
  overflow: hidden;
}

.ticker-track {
  display: flex;
  gap: 48px;
  animation: tickerScroll 30s linear infinite;
  white-space: nowrap;
}

.ticker-item {
  font-size: 13px;
  color: var(--text-muted);
  flex-shrink: 0;
}

.ticker-item strong {
  color: var(--text-bright);
}

@keyframes tickerScroll {
  0% { transform: translateX(0); }
  100% { transform: translateX(-50%); }
}

/* ============================================
   SECTIONS
   ============================================ */
.section {
  padding: 100px 24px;
  max-width: 1400px;
  margin: 0 auto;
}

.section-dark {
  max-width: 100%;
  padding-left: max(24px, calc((100% - 1400px) / 2));
  padding-right: max(24px, calc((100% - 1400px) / 2));
  background: var(--surface);
  border-top: 1px solid var(--border);
  border-bottom: 1px solid var(--border);
}

.section-header {
  display: flex;
  justify-content: space-between;
  align-items: flex-end;
  margin-bottom: 48px;
  flex-wrap: wrap;
  gap: 24px;
}

.section-tag {
  display: inline-block;
  font-size: 12px;
  font-weight: 600;
  text-transform: uppercase;
  letter-spacing: 2px;
  color: var(--accent);
  margin-bottom: 8px;
}

.section-title {
  font-family: var(--font-display);
  font-size: clamp(28px, 4vw, 44px);
  font-weight: 700;
  color: var(--text-bright);
  line-height: 1.2;
}

/* Filters */
.section-filters {
  display: flex;
  gap: 8px;
  flex-wrap: wrap;
}

.filter-btn {
  padding: 8px 20px;
  font-size: 13px;
  font-weight: 500;
  color: var(--text-muted);
  border: 1px solid var(--border);
  border-radius: 100px;
  transition: var(--transition);
}

.filter-btn:hover {
  color: var(--text-bright);
  border-color: var(--accent-dark);
}

.filter-btn.active {
  color: var(--bg);
  background: var(--accent);
  border-color: var(--accent);
  font-weight: 600;
}

/* ============================================
   PRODUCT GRID
   ============================================ */
.product-grid {
  display: grid;
  grid-template-columns: repeat(auto-fill, minmax(280px, 1fr));
  gap: 24px;
}

.product-card {
  background: var(--surface);
  border: 1px solid var(--border);
  border-radius: var(--radius-lg);
  overflow: hidden;
  transition: var(--transition);
  position: relative;
  animation: fadeInUp 0.5s ease-out both;
}

.product-card:hover {
  transform: translateY(-4px);
  border-color: rgba(102, 252, 241, 0.3);
  box-shadow: 0 12px 40px rgba(0,0,0,0.4), 0 0 20px rgba(102, 252, 241, 0.05);
}

.product-image {
  position: relative;
  aspect-ratio: 4/3;
  overflow: hidden;
  background: var(--surface-light);
}

.product-image img {
  width: 100%;
  height: 100%;
  object-fit: cover;
  transition: transform 0.6s ease;
}

.product-card:hover .product-image img {
  transform: scale(1.08);
}

.product-badge {
  position: absolute;
  top: 12px;
  left: 12px;
  padding: 4px 12px;
  font-size: 11px;
  font-weight: 600;
  text-transform: uppercase;
  letter-spacing: 1px;
  border-radius: 100px;
  background: rgba(11, 12, 16, 0.8);
  backdrop-filter: blur(8px);
  color: var(--gold);
  border: 1px solid rgba(255, 215, 0, 0.3);
}

.product-badge.sale {
  color: var(--danger);
  border-color: rgba(239, 68, 68, 0.3);
}

.product-wishlist {
  position: absolute;
  top: 12px;
  right: 12px;
  width: 36px;
  height: 36px;
  display: flex;
  align-items: center;
  justify-content: center;
  border-radius: 50%;
  background: rgba(11, 12, 16, 0.6);
  backdrop-filter: blur(8px);
  color: var(--text-muted);
  transition: var(--transition);
}

.product-wishlist:hover {
  color: var(--danger);
  background: rgba(239, 68, 68, 0.15);
}

.product-wishlist.active {
  color: var(--danger);
}

.product-info {
  padding: 20px;
}

.product-category {
  font-size: 11px;
  font-weight: 600;
  text-transform: uppercase;
  letter-spacing: 1.5px;
  color: var(--accent-dark);
  margin-bottom: 6px;
}

.product-title-card {
  font-family: var(--font-display);
  font-size: 18px;
  font-weight: 600;
  color: var(--text-bright);
  margin-bottom: 4px;
}

.product-desc {
  font-size: 13px;
  color: var(--text-muted);
  margin-bottom: 16px;
  line-height: 1.5;
}

.product-footer {
  display: flex;
  align-items: center;
  justify-content: space-between;
}

.product-price-card {
  font-size: 20px;
  font-weight: 700;
  color: var(--gold);
}

.product-rating {
  display: flex;
  align-items: center;
  gap: 4px;
  font-size: 13px;
  color: var(--text-muted);
}

.product-rating .stars {
  color: var(--gold);
}

.product-add-btn {
  width: 40px;
  height: 40px;
  display: flex;
  align-items: center;
  justify-content: center;
  border-radius: 10px;
  background: rgba(102, 252, 241, 0.08);
  color: var(--accent);
  transition: var(--transition);
}

.product-add-btn:hover {
  background: var(--accent);
  color: var(--bg);
  transform: scale(1.1);
}

.product-add-btn.added {
  background: var(--success);
  color: white;
}

/* ============================================
   DASHBOARD
   ============================================ */
.dashboard-status {
  display: flex;
  align-items: center;
  gap: 8px;
  font-size: 13px;
  color: var(--text-muted);
}

.dashboard-grid {
  display: grid;
  grid-template-columns: repeat(4, 1fr);
  gap: 20px;
}

/* Metric Cards */
.metric-card {
  background: var(--bg);
  border: 1px solid var(--border);
  border-radius: var(--radius);
  padding: 24px;
  transition: var(--transition);
}

.metric-card:hover {
  border-color: rgba(102, 252, 241, 0.2);
}

.metric-header {
  display: flex;
  justify-content: space-between;
  align-items: center;
  margin-bottom: 12px;
}

.metric-icon {
  font-size: 20px;
}

.metric-trend {
  font-size: 12px;
  font-weight: 600;
  padding: 2px 8px;
  border-radius: 100px;
}

.metric-trend.up {
  color: var(--success);
  background: rgba(34, 197, 94, 0.1);
}

.metric-trend.down {
  color: var(--danger);
  background: rgba(239, 68, 68, 0.1);
}

.metric-value {
  font-family: var(--font-display);
  font-size: 28px;
  font-weight: 700;
  color: var(--text-bright);
  margin-bottom: 4px;
}

.metric-label {
  font-size: 13px;
  color: var(--text-muted);
  margin-bottom: 16px;
}

.metric-sparkline {
  height: 40px;
  display: flex;
  align-items: flex-end;
  gap: 2px;
}

.spark-bar {
  flex: 1;
  border-radius: 2px;
  min-height: 4px;
  transition: height 0.5s ease;
}

/* Chart Cards */
.chart-card {
  background: var(--bg);
  border: 1px solid var(--border);
  border-radius: var(--radius);
  padding: 24px;
}

.chart-main {
  grid-column: span 2;
}

.chart-header {
  display: flex;
  justify-content: space-between;
  align-items: center;
  margin-bottom: 24px;
  flex-wrap: wrap;
  gap: 12px;
}

.chart-title {
  font-family: var(--font-display);
  font-size: 18px;
  font-weight: 600;
  color: var(--text-bright);
}

.chart-tabs {
  display: flex;
  gap: 4px;
  background: var(--surface);
  border-radius: 8px;
  padding: 3px;
}

.chart-tab {
  padding: 6px 14px;
  font-size: 12px;
  font-weight: 500;
  color: var(--text-muted);
  border-radius: 6px;
  transition: var(--transition);
}

.chart-tab.active {
  background: var(--accent);
  color: var(--bg);
  font-weight: 600;
}

.chart-container {
  height: 250px;
  position: relative;
}

.chart-svg {
  width: 100%;
  height: 100%;
}

/* Category Bars */
.category-bars {
  display: flex;
  flex-direction: column;
  gap: 16px;
}

.category-bar-item {
  display: flex;
  flex-direction: column;
  gap: 6px;
}

.category-bar-label {
  display: flex;
  justify-content: space-between;
  font-size: 13px;
  color: var(--text-muted);
}

.category-bar-label strong {
  color: var(--text-bright);
}

.category-bar-track {
  height: 8px;
  background: var(--surface-light);
  border-radius: 4px;
  overflow: hidden;
}

.category-bar-fill {
  height: 100%;
  border-radius: 4px;
  transition: width 1s ease;
  background: linear-gradient(90deg, var(--accent-dark), var(--accent));
}

/* Transaction List */
.transaction-list {
  display: flex;
  flex-direction: column;
  gap: 12px;
}

.transaction-item {
  display: flex;
  align-items: center;
  gap: 12px;
  padding: 12px;
  background: var(--surface);
  border-radius: 10px;
  transition: var(--transition);
}

.transaction-item:hover {
  background: var(--surface-light);
}

.transaction-avatar {
  width: 36px;
  height: 36px;
  border-radius: 50%;
  display: flex;
  align-items: center;
  justify-content: center;
  font-size: 14px;
  font-weight: 600;
  color: var(--bg);
  flex-shrink: 0;
}

.transaction-info {
  flex: 1;
  min-width: 0;
}

.transaction-name {
  font-size: 14px;
  font-weight: 500;
  color: var(--text-bright);
}

.transaction-product {
  font-size: 12px;
  color: var(--text-muted);
}

.transaction-amount {
  font-size: 14px;
  font-weight: 600;
  color: var(--gold);
  flex-shrink: 0;
}

.transaction-time {
  font-size: 11px;
  color: var(--text-muted);
  flex-shrink: 0;
}

/* Top Products */
.top-products {
  display: flex;
  flex-direction: column;
  gap: 12px;
}

.top-product-item {
  display: flex;
  align-items: center;
  gap: 12px;
  padding: 10px;
  border-radius: 10px;
  transition: var(--transition);
}

.top-product-item:hover {
  background: var(--surface);
}

.top-product-rank {
  width: 24px;
  height: 24px;
  display: flex;
  align-items: center;
  justify-content: center;
  font-size: 12px;
  font-weight: 700;
  border-radius: 6px;
  background: rgba(102, 252, 241, 0.1);
  color: var(--accent);
  flex-shrink: 0;
}

.top-product-item:nth-child(1) .top-product-rank {
  background: rgba(255, 215, 0, 0.15);
  color: var(--gold);
}

.top-product-img {
  width: 40px;
  height: 40px;
  border-radius: 8px;
  overflow: hidden;
  flex-shrink: 0;
}

.top-product-img img {
  width: 100%;
  height: 100%;
  object-fit: cover;
}

.top-product-info {
  flex: 1;
}

.top-product-name {
  font-size: 14px;
  font-weight: 500;
  color: var(--text-bright);
}

.top-product-sales {
  font-size: 12px;
  color: var(--text-muted);
}

.top-product-revenue {
  font-size: 14px;
  font-weight: 600;
  color: var(--accent);
}

/* ============================================
   FEATURES
   ============================================ */
.features-grid {
  display: grid;
  grid-template-columns: repeat(auto-fit, minmax(260px, 1fr));
  gap: 24px;
}

.feature-card {
  padding: 32px;
  background: var(--surface);
  border: 1px solid var(--border);
  border-radius: var(--radius-lg);
  transition: var(--transition);
}

.feature-card:hover {
  transform: translateY(-4px);
  border-color: rgba(102, 252, 241, 0.2);
  box-shadow: 0 12px 40px rgba(0,0,0,0.3);
}

.feature-icon {
  font-size: 32px;
  margin-bottom: 16px;
}

.feature-title {
  font-family: var(--font-display);
  font-size: 20px;
  font-weight: 600;
  color: var(--text-bright);
  margin-bottom: 8px;
}

.feature-desc {
  font-size: 14px;
  color: var(--text-muted);
  line-height: 1.6;
}

/* ============================================
   FOOTER
   ============================================ */
.footer {
  background: var(--surface);
  border-top: 1px solid var(--border);
  padding: 60px 24px 24px;
}

.footer-inner {
  max-width: 1400px;
  margin: 0 auto;
  display: flex;
  justify-content: space-between;
  gap: 60px;
  flex-wrap: wrap;
  margin-bottom: 40px;
}

.footer-brand {
  max-width: 300px;
}

.footer-brand .brand-mark {
  font-size: 28px;
}

.footer-brand .brand-name {
  display: block;
  margin: 8px 0 12px;
}

.footer-tagline {
  font-size: 14px;
  color: var(--text-muted);
}

.footer-links {
  display: flex;
  gap: 60px;
  flex-wrap: wrap;
}

.footer-col h4 {
  font-size: 13px;
  font-weight: 600;
  text-transform: uppercase;
  letter-spacing: 1.5px;
  color: var(--text-bright);
  margin-bottom: 16px;
}

.footer-col a {
  display: block;
  font-size: 14px;
  color: var(--text-muted);
  padding: 4px 0;
  transition: var(--transition);
}

.footer-col a:hover {
  color: var(--accent);
}

.footer-bottom {
  max-width: 1400px;
  margin: 0 auto;
  padding-top: 24px;
  border-top: 1px solid var(--border);
  display: flex;
  justify-content: space-between;
  font-size: 13px;
  color: var(--text-muted);
  flex-wrap: wrap;
  gap: 12px;
}

/* ============================================
   CART DRAWER
   ============================================ */
.cart-overlay {
  position: fixed;
  inset: 0;
  background: rgba(0,0,0,0.6);
  backdrop-filter: blur(4px);
  z-index: 200;
  opacity: 0;
  pointer-events: none;
  transition: opacity 0.3s ease;
}

.cart-overlay.open {
  opacity: 1;
  pointer-events: all;
}

.cart-drawer {
  position: fixed;
  top: 0;
  right: 0;
  bottom: 0;
  width: 400px;
  max-width: 100vw;
  background: var(--surface);
  border-left: 1px solid var(--border);
  z-index: 201;
  display: flex;
  flex-direction: column;
  transform: translateX(100%);
  transition: transform 0.4s cubic-bezier(0.4, 0, 0.2, 1);
}

.cart-drawer.open {
  transform: translateX(0);
}

.cart-header {
  display: flex;
  justify-content: space-between;
  align-items: center;
  padding: 20px 24px;
  border-bottom: 1px solid var(--border);
}

.cart-header h3 {
  font-family: var(--font-display);
  font-size: 20px;
  font-weight: 600;
  color: var(--text-bright);
}

.cart-close {
  width: 36px;
  height: 36px;
  display: flex;
  align-items: center;
  justify-content: center;
  border-radius: 8px;
  color: var(--text-muted);
  font-size: 16px;
  transition: var(--transition);
}

.cart-close:hover {
  background: var(--surface-light);
  color: var(--text-bright);
}

.cart-items {
  flex: 1;
  overflow-y: auto;
  padding: 16px 24px;
  display: flex;
  flex-direction: column;
  gap: 16px;
}

.cart-empty {
  text-align: center;
  padding: 60px 20px;
  color: var(--text-muted);
  font-size: 14px;
}

.cart-item {
  display: flex;
  gap: 12px;
  padding: 12px;
  background: var(--bg);
  border-radius: 10px;
  border: 1px solid var(--border);
}

.cart-item-img {
  width: 60px;
  height: 60px;
  border-radius: 8px;
  overflow: hidden;
  flex-shrink: 0;
}

.cart-item-img img {
  width: 100%;
  height: 100%;
  object-fit: cover;
}

.cart-item-info {
  flex: 1;
  min-width: 0;
}

.cart-item-name {
  font-size: 14px;
  font-weight: 500;
  color: var(--text-bright);
  margin-bottom: 2px;
}

.cart-item-price {
  font-size: 14px;
  font-weight: 600;
  color: var(--gold);
}

.cart-item-remove {
  font-size: 12px;
  color: var(--text-muted);
  background: none;
  border: none;
  cursor: pointer;
  padding: 4px 0;
  transition: var(--transition);
}

.cart-item-remove:hover {
  color: var(--danger);
}

.cart-footer {
  padding: 20px 24px;
  border-top: 1px solid var(--border);
}

.cart-total {
  display: flex;
  justify-content: space-between;
  align-items: center;
  margin-bottom: 16px;
  font-size: 16px;
  font-weight: 600;
  color: var(--text-bright);
}

.cart-total span:last-child {
  font-family: var(--font-display);
  font-size: 22px;
  color: var(--gold);
}

/* ============================================
   TOAST
   ============================================ */
.toast-container {
  position: fixed;
  bottom: 24px;
  right: 24px;
  z-index: 300;
  display: flex;
  flex-direction: column;
  gap: 8px;
}

.toast {
  padding: 14px 20px;
  background: var(--surface);
  border: 1px solid rgba(102, 252, 241, 0.3);
  border-radius: 10px;
  color: var(--text-bright);
  font-size: 14px;
  box-shadow: var(--shadow-lg);
  animation: toastIn 0.4s ease-out;
  display: flex;
  align-items: center;
  gap: 10px;
}

.toast.removing {
  animation: toastOut 0.3s ease-in forwards;
}

@keyframes toastIn {
  from { opacity: 0; transform: translateX(100px); }
  to { opacity: 1; transform: translateX(0); }
}

@keyframes toastOut {
  from { opacity: 1; transform: translateX(0); }
  to { opacity: 0; transform: translateX(100px); }
}

/* ============================================
   RESPONSIVE
   ============================================ */
@media (max-width: 1024px) {
  .hero-content {
    grid-template-columns: 1fr;
    text-align: center;
  }

  .hero-text {
    order: 1;
  }

  .hero-visual {
    order: 0;
  }

  .hero-subtitle {
    margin-left: auto;
    margin-right: auto;
  }

  .hero-cta {
    justify-content: center;
  }

  .hero-stats {
    justify-content: center;
  }

  .dashboard-grid {
    grid-template-columns: repeat(2, 1fr);
  }

  .chart-main {
    grid-column: span 2;
  }
}

@media (max-width: 768px) {
  .nav-links {
    display: none;
  }

  .hero {
    padding: 80px 16px 40px;
  }

  .hero-product-ring {
    width: 280px;
    height: 280px;
  }

  .hero-product-image {
    width: 200px;
    height: 200px;
  }

  .hero-stats {
    gap: 20px;
  }

  .section {
    padding: 60px 16px;
  }

  .section-dark {
    padding-left: 16px;
    padding-right: 16px;
  }

  .product-grid {
    grid-template-columns: 1fr;
  }

  .dashboard-grid {
    grid-template-columns: 1fr;
  }

  .chart-main {
    grid-column: span 1;
  }

  .features-grid {
    grid-template-columns: 1fr;
  }

  .footer-inner {
    flex-direction: column;
    gap: 32px;
  }

  .footer-links {
    gap: 32px;
  }

  .cart-drawer {
    width: 100%;
  }
}

@media (max-width: 480px) {
  .hero-title {
    font-size: 36px;
  }

  .hero-stats {
    flex-direction: column;
    gap: 16px;
  }

  .section-filters {
    width: 100%;
    overflow-x: auto;
    flex-wrap: nowrap;
    padding-bottom: 8px;
  }

  .filter-btn {
    flex-shrink: 0;
  }
}

/* ============================================
   REDUCED MOTION
   ============================================ */
@media (prefers-reduced-motion: reduce) {
  *, *::before, *::after {
    animation-duration: 0.01ms !important;
    animation-iteration-count: 1 !important;
    transition-duration: 0.01ms !important;
  }

  html {
    scroll-behavior: auto;
  }
}
